    "sourcePythonCode": "class Solution:\n    def gcdOfStrings(self, str1: str, str2: str) -> str:\n        def check(a, b):\n            c = \"\"\n            while len(c) < len(b):\n                c += a\n            return c == b\n\n        for i in range(min(len(str1), len(str2)), 0, -1):\n            t = str1[:i]\n            if check(t, str1) and check(t, str2):\n                return t\n        return ''",
