    "sourcePythonCode": "class Solution:\n    def canPlaceFlowers(self, flowerbed: List[int], n: int) -> bool:\n        flowerbed = [0] + flowerbed + [0]\n        for i in range(1, len(flowerbed) - 1):\n            if sum(flowerbed[i - 1 : i + 2]) == 0:\n                flowerbed[i] = 1\n                n -= 1\n        return n <= 0",
    "sourceGoCode": "func canPlaceFlowers(flowerbed []int, n int) bool {\n\tm := len(flowerbed)\n\tfor i, v := range flowerbed {\n\t\tl, r := 0, 0\n\t\tif i > 0 {\n\t\t\tl = flowerbed[i-1]\n\t\t}\n\t\tif i < m-1 {\n\t\t\tr = flowerbed[i+1]\n\t\t}\n\t\tif l+v+r == 0 {\n\t\t\tflowerbed[i] = 1\n\t\t\tn--\n\t\t}\n\t}\n\treturn n <= 0\n}",
