    "sourcePythonCode": "class Solution:\n    def reverseWords(self, s: str) -> str:\n        words = []\n        i, n = 0, len(s)\n        while i < n:\n            while i < n and s[i] == \" \":\n                i += 1\n            if i < n:\n                j = i\n                while j < n and s[j] != \" \":\n                    j += 1\n                words.append(s[i:j])\n                i = j\n        return \" \".join(words[::-1])",
    "sourceGoCode": "func reverseWords(s string) string {\n\twords := []string{}\n\ti, n := 0, len(s)\n\tfor i < n {\n\t\tfor i < n && s[i] == ' ' {\n\t\t\ti++\n\t\t}\n\t\tif i < n {\n\t\t\tj := i\n\t\t\tt := []byte{}\n\t\t\tfor j < n && s[j] != ' ' {\n\t\t\t\tt = append(t, s[j])\n\t\t\t\tj++\n\t\t\t}\n\t\t\twords = append(words, string(t))\n\t\t\ti = j\n\t\t}\n\t}\n\tfor i, j := 0, len(words)-1; i < j; i, j = i+1, j-1 {\n\t\twords[i], words[j] = words[j], words[i]\n\t}\n\treturn strings.Join(words, \" \")\n}",
