    "sourcePythonCode": "class Solution:\n    def findMaxAverage(self, nums: List[int], k: int) -> float:\n        ans = s = sum(nums[:k])\n        for i in range(k, len(nums)):\n            s += nums[i] - nums[i - k]\n            ans = max(ans, s)\n        return ans / k",
