    "sourcePythonCode": "class Solution:\n    def longestOnes(self, nums: List[int], k: int) -> int:\n        l = cnt = 0\n        for x in nums:\n            cnt += x ^ 1\n            if cnt > k:\n                cnt -= nums[l] ^ 1\n                l += 1\n        return len(nums) - l",
