    "sourcePythonCode": "class Solution:\n    def closeStrings(self, word1: str, word2: str) -> bool:\n        cnt1, cnt2 = Counter(word1), Counter(word2)\n        return sorted(cnt1.values()) == sorted(cnt2.values()) and set(\n            cnt1.keys()\n        ) == set(cnt2.keys())",
    "sourceGoCode": "func closeStrings(word1 string, word2 string) bool {\n\tcnt1 := make([]int, 26)\n\tcnt2 := make([]int, 26)\n\tfor _, c := range word1 {\n\t\tcnt1[c-'a']++\n\t}\n\tfor _, c := range word2 {\n\t\tcnt2[c-'a']++\n\t}\n\tif !slices.EqualFunc(cnt1, cnt2, func(v1, v2 int) bool { return (v1 == 0) == (v2 == 0) }) {\n\t\treturn false\n\t}\n\tsort.Ints(cnt1)\n\tsort.Ints(cnt2)\n\treturn slices.Equal(cnt1, cnt2)\n}",
