    "sourcePythonCode": "class Solution:\n    def asteroidCollision(self, asteroids: List[int]) -> List[int]:\n        stk = []\n        for x in asteroids:\n            if x > 0:\n                stk.append(x)\n            else:\n                while stk and stk[-1] > 0 and stk[-1] < -x:\n                    stk.pop()\n                if stk and stk[-1] == -x:\n                    stk.pop()\n                elif not stk or stk[-1] < 0:\n                    stk.append(x)\n        return stk",
