    "leetcodeMainPath": "leetcode-main/solution/0300-0399/0394.Decode String",
    "sourcePythonCode": "class Solution:\n    def decodeString(self, s: str) -> str:\n        s1, s2 = [], []\n        num, res = 0, ''\n        for c in s:\n            if c.isdigit():\n                num = num * 10 + int(c)\n            elif c == '[':\n                s1.append(num)\n                s2.append(res)\n                num, res = 0, ''\n            elif c == ']':\n                res = s2.pop() + res * s1.pop()\n            else:\n                res += c\n        return res",
