    "sourcePythonCode": "# Definition for a binary tree node.\n# class TreeNode:\n#     def __init__(self, val=0, left=None, right=None):\n#         self.val = val\n#         self.left = left\n#         self.right = right\nclass Solution:\n    def pathSum(self, root: Optional[TreeNode], targetSum: int) -> int:\n        def dfs(node, s):\n            if node is None:\n                return 0\n            s += node.val\n            ans = cnt[s - targetSum]\n            cnt[s] += 1\n            ans += dfs(node.left, s)\n            ans += dfs(node.right, s)\n            cnt[s] -= 1\n            return ans\n\n        cnt = Counter({0: 1})\n        return dfs(root, 0)",
    "sourceGoCode": "/**\n * Definition for a binary tree node.\n * type TreeNode struct {\n *     Val int\n *     Left *TreeNode\n *     Right *TreeNode\n * }\n */\nfunc pathSum(root *TreeNode, targetSum int) int {\n\tcnt := map[int]int{0: 1}\n\tvar dfs func(*TreeNode, int) int\n\tdfs = func(node *TreeNode, s int) int {\n\t\tif node == nil {\n\t\t\treturn 0\n\t\t}\n\t\ts += node.Val\n\t\tans := cnt[s-targetSum]\n\t\tcnt[s]++\n\t\tans += dfs(node.Left, s) + dfs(node.Right, s)\n\t\tcnt[s]--\n\t\treturn ans\n\t}\n\treturn dfs(root, 0)\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 437. Path Sum III.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\npath_sum_iii = solve\n\n\nif __name__ == \"__main__\":\n    print(\"437. Path Sum III\")\n    print('Sample input:', \"root=[10,5,-3,3,2,null,11,3,-2,null,1], targetSum=8\")\n    print('Expected output:', \"3\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
