    "leetcodeMainPath": "leetcode-main/solution/0300-0399/0399.Evaluate Division",
    "sourcePythonCode": "class Solution:\n    def calcEquation(\n        self, equations: List[List[str]], values: List[float], queries: List[List[str]]\n    ) -> List[float]:\n        def find(x):\n            if p[x] != x:\n                origin = p[x]\n                p[x] = find(p[x])\n                w[x] *= w[origin]\n            return p[x]\n\n        w = defaultdict(lambda: 1)\n        p = defaultdict()\n        for a, b in equations:\n            p[a], p[b] = a, b\n        for i, v in enumerate(values):\n            a, b = equations[i]\n            pa, pb = find(a), find(b)\n            if pa == pb:\n                continue\n            p[pa] = pb\n            w[pa] = w[b] * v / w[a]\n        return [\n            -1 if c not in p or d not in p or find(c) != find(d) else w[c] / w[d]\n            for c, d in queries\n        ]",
    "sourceGoCode": "func calcEquation(equations [][]string, values []float64, queries [][]string) []float64 {\n\tp := make(map[string]string)\n\tw := make(map[string]float64)\n\tfor _, e := range equations {\n\t\ta, b := e[0], e[1]\n\t\tp[a], p[b] = a, b\n\t\tw[a], w[b] = 1.0, 1.0\n\t}\n\n\tvar find func(x string) string\n\tfind = func(x string) string {\n\t\tif p[x] != x {\n\t\t\torigin := p[x]\n\t\t\tp[x] = find(p[x])\n\t\t\tw[x] *= w[origin]\n\t\t}\n\t\treturn p[x]\n\t}\n\n\tfor i, v := range values {\n\t\ta, b := equations[i][0], equations[i][1]\n\t\tpa, pb := find(a), find(b)\n\t\tif pa == pb {\n\t\t\tcontinue\n\t\t}\n\t\tp[pa] = pb\n\t\tw[pa] = w[b] * v / w[a]\n\t}\n\tvar ans []float64\n\tfor _, e := range queries {\n\t\tc, d := e[0], e[1]\n\t\tif p[c] == \"\" || p[d] == \"\" || find(c) != find(d) {\n\t\t\tans = append(ans, -1.0)\n\t\t} else {\n\t\t\tans = append(ans, w[c]/w[d])\n\t\t}\n\t}\n\treturn ans\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 399. Evaluate Division.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    graph = {}\n    for a, b in (args[1] if len(args) > 1 else []):\n        graph.setdefault(a, []).append(b)\n        graph.setdefault(b, []).append(a)\n    return graph\n\n\n\nevaluate_division = solve\n\n\nif __name__ == \"__main__\":\n    print(\"399. Evaluate Division\")\n    print('Sample input:', \"equations=[[\\\"a\\\",\\\"b\\\"],[\\\"b\\\",\\\"c\\\"]], values=[2,3], queries=[[\\\"a\\\",\\\"c\\\"],[\\\"c\\\",\\\"a\\\"],[\\\"x\\\",\\\"y\\\"]]\")\n    print('Expected output:', \"[6.0,0.16667,-1.0]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 399. Evaluate Division\nfunc Solve046(args ...any) any {\n\treturn args\n}\n\nfunc main() {\n\tfmt.Println(\"399. Evaluate Division\")\n\tfmt.Println(\"Sample input:\", \"equations=[[\\\"a\\\",\\\"b\\\"],[\\\"b\\\",\\\"c\\\"]], values=[2,3], queries=[[\\\"a\\\",\\\"c\\\"],[\\\"c\\\",\\\"a\\\"],[\\\"x\\\",\\\"y\\\"]]\")\n\tfmt.Println(\"Expected output:\", \"[6.0,0.16667,-1.0]\")\n\tfmt.Println(\"Call Solve046(...) with parsed arguments for this problem.\")\n}\n"
