    "leetcodeMainPath": "leetcode-main/solution/2400-2499/2462.Total Cost to Hire K Workers",
    "sourcePythonCode": "class Solution:\n    def totalCost(self, costs: List[int], k: int, candidates: int) -> int:\n        n = len(costs)\n        if candidates * 2 >= n:\n            return sum(sorted(costs)[:k])\n        pq = []\n        for i, c in enumerate(costs[:candidates]):\n            heappush(pq, (c, i))\n        for i in range(n - candidates, n):\n            heappush(pq, (costs[i], i))\n        heapify(pq)\n        l, r = candidates, n - candidates - 1\n        ans = 0\n        for _ in range(k):\n            c, i = heappop(pq)\n            ans += c\n            if l > r:\n                continue\n            if i < l:\n                heappush(pq, (costs[l], l))\n                l += 1\n            else:\n                heappush(pq, (costs[r], r))\n                r -= 1\n        return ans",
    "sourceGoCode": "func totalCost(costs []int, k int, candidates int) (ans int64) {\n\tn := len(costs)\n\tif candidates*2 > n {\n\t\tsort.Ints(costs)\n\t\tfor _, x := range costs[:k] {\n\t\t\tans += int64(x)\n\t\t}\n\t\treturn\n\t}\n\tpq := hp{}\n\tfor i, x := range costs[:candidates] {\n\t\theap.Push(&pq, pair{x, i})\n\t\theap.Push(&pq, pair{costs[n-i-1], n - i - 1})\n\t}\n\tl, r := candidates, n-candidates-1\n\tfor ; k > 0; k-- {\n\t\tp := heap.Pop(&pq).(pair)\n\t\tans += int64(p.cost)\n\t\tif l > r {\n\t\t\tcontinue\n\t\t}\n\t\tif p.i < l {\n\t\t\theap.Push(&pq, pair{costs[l], l})\n\t\t\tl++\n\t\t} else {\n\t\t\theap.Push(&pq, pair{costs[r], r})\n\t\t\tr--\n\t\t}\n\t}\n\treturn\n}\n\ntype pair struct{ cost, i int }\ntype hp []pair\n\nfunc (h hp) Len() int { return len(h) }\nfunc (h hp) Less(i, j int) bool {\n\treturn h[i].cost < h[j].cost || (h[i].cost == h[j].cost && h[i].i < h[j].i)\n}\nfunc (h hp) Swap(i, j int) { h[i], h[j] = h[j], h[i] }\nfunc (h *hp) Push(v any)   { *h = append(*h, v.(pair)) }\nfunc (h *hp) Pop() any     { a := *h; v := a[len(a)-1]; *h = a[:len(a)-1]; return v }",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 2462. Total Cost to Hire K Workers.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\ntotal_cost_to_hire_k_workers = solve\n\n\nif __name__ == \"__main__\":\n    print(\"2462. Total Cost to Hire K Workers\")\n    print('Sample input:', \"costs=[17,12,10,2,7,2,11,20,8], k=3, candidates=4\")\n    print('Expected output:', \"11\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
