    "sourcePythonCode": "class Solution:\n    def minEatingSpeed(self, piles: List[int], h: int) -> int:\n        def check(k: int) -> bool:\n            return sum((x + k - 1) // k for x in piles) <= h\n\n        return 1 + bisect_left(range(1, max(piles) + 1), True, key=check)",
