    "sourcePythonCode": "class Solution:\n    def longestCommonSubsequence(self, text1: str, text2: str) -> int:\n        m, n = len(text1), len(text2)\n        f = [[0] * (n + 1) for _ in range(m + 1)]\n        for i in range(1, m + 1):\n            for j in range(1, n + 1):\n                if text1[i - 1] == text2[j - 1]:\n                    f[i][j] = f[i - 1][j - 1] + 1\n                else:\n                    f[i][j] = max(f[i - 1][j], f[i][j - 1])\n        return f[m][n]",
    "sourceGoCode": "func longestCommonSubsequence(text1 string, text2 string) int {\n\tm, n := len(text1), len(text2)\n\tf := make([][]int, m+1)\n\tfor i := range f {\n\t\tf[i] = make([]int, n+1)\n\t}\n\tfor i := 1; i <= m; i++ {\n\t\tfor j := 1; j <= n; j++ {\n\t\t\tif text1[i-1] == text2[j-1] {\n\t\t\t\tf[i][j] = f[i-1][j-1] + 1\n\t\t\t} else {\n\t\t\t\tf[i][j] = max(f[i-1][j], f[i][j-1])\n\t\t\t}\n\t\t}\n\t}\n\treturn f[m][n]\n}",
