    "sourcePythonCode": "class Solution:\n    def minFlips(self, a: int, b: int, c: int) -> int:\n        ans = 0\n        for i in range(32):\n            x, y, z = a >> i & 1, b >> i & 1, c >> i & 1\n            ans += x + y if z == 0 else int(x == 0 and y == 0)\n        return ans",
    "sourceGoCode": "func minFlips(a int, b int, c int) (ans int) {\n\tfor i := 0; i < 32; i++ {\n\t\tx, y, z := a>>i&1, b>>i&1, c>>i&1\n\t\tif z == 0 {\n\t\t\tans += x + y\n\t\t} else if x == 0 && y == 0 {\n\t\t\tans++\n\t\t}\n\t}\n\treturn\n}",
