    "leetcodeMainPath": "leetcode-main/solution/0200-0299/0208.Implement Trie (Prefix Tree)",
    "sourcePythonCode": "class Trie:\n    def __init__(self):\n        self.children = [None] * 26\n        self.is_end = False\n\n    def insert(self, word: str) -> None:\n        node = self\n        for c in word:\n            idx = ord(c) - ord('a')\n            if node.children[idx] is None:\n                node.children[idx] = Trie()\n            node = node.children[idx]\n        node.is_end = True\n\n    def search(self, word: str) -> bool:\n        node = self._search_prefix(word)\n        return node is not None and node.is_end\n\n    def startsWith(self, prefix: str) -> bool:\n        node = self._search_prefix(prefix)\n        return node is not None\n\n    def _search_prefix(self, prefix: str):\n        node = self\n        for c in prefix:\n            idx = ord(c) - ord('a')\n            if node.children[idx] is None:\n                return None\n            node = node.children[idx]\n        return node\n\n\n# Your Trie object will be instantiated and called as such:\n# obj = Trie()\n# obj.insert(word)\n# param_2 = obj.search(word)\n# param_3 = obj.startsWith(prefix)",
    "sourceGoCode": "type Trie struct {\n\tchildren [26]*Trie\n\tisEnd    bool\n}\n\nfunc Constructor() Trie {\n\treturn Trie{}\n}\n\nfunc (this *Trie) Insert(word string) {\n\tnode := this\n\tfor _, c := range word {\n\t\tidx := c - 'a'\n\t\tif node.children[idx] == nil {\n\t\t\tnode.children[idx] = &Trie{}\n\t\t}\n\t\tnode = node.children[idx]\n\t}\n\tnode.isEnd = true\n}\n\nfunc (this *Trie) Search(word string) bool {\n\tnode := this.SearchPrefix(word)\n\treturn node != nil && node.isEnd\n}\n\nfunc (this *Trie) StartsWith(prefix string) bool {\n\tnode := this.SearchPrefix(prefix)\n\treturn node != nil\n}\n\nfunc (this *Trie) SearchPrefix(s string) *Trie {\n\tnode := this\n\tfor _, c := range s {\n\t\tidx := c - 'a'\n\t\tif node.children[idx] == nil {\n\t\t\treturn nil\n\t\t}\n\t\tnode = node.children[idx]\n\t}\n\treturn node\n}\n\n/**\n * Your Trie object will be instantiated and called as such:\n * obj := Constructor();\n * obj.Insert(word);\n * param_2 := obj.Search(word);\n * param_3 := obj.StartsWith(prefix);\n */",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 208. Implement Trie (Prefix Tree).\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nimplement_trie_prefix_tree = solve\n\n\nif __name__ == \"__main__\":\n    print(\"208. Implement Trie (Prefix Tree)\")\n    print('Sample input:', \"insert(\\\"apple\\\"), search(\\\"apple\\\"), startsWith(\\\"app\\\")\")\n    print('Expected output:', \"[null,true,true]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 208. Implement Trie (Prefix Tree)\nfunc Solve070(args ...any) any {\n\tanswer := make([]any, 0, len(args))\n\tanswer = append(answer, args...)\n\treturn answer\n}\n\nfunc main() {\n\tfmt.Println(\"208. Implement Trie (Prefix Tree)\")\n\tfmt.Println(\"Sample input:\", \"insert(\\\"apple\\\"), search(\\\"apple\\\"), startsWith(\\\"app\\\")\")\n\tfmt.Println(\"Expected output:\", \"[null,true,true]\")\n\tfmt.Println(\"Call Solve070(...) with parsed arguments for this problem.\")\n}\n"
