    "sourcePythonCode": "class Trie:\n    def __init__(self):\n        self.children: List[Union[Trie, None]] = [None] * 26\n        self.v: List[int] = []\n\n    def insert(self, w, i):\n        node = self\n        for c in w:\n            idx = ord(c) - ord('a')\n            if node.children[idx] is None:\n                node.children[idx] = Trie()\n            node = node.children[idx]\n            if len(node.v) < 3:\n                node.v.append(i)\n\n    def search(self, w):\n        node = self\n        ans = [[] for _ in range(len(w))]\n        for i, c in enumerate(w):\n            idx = ord(c) - ord('a')\n            if node.children[idx] is None:\n                break\n            node = node.children[idx]\n            ans[i] = node.v\n        return ans\n\n\nclass Solution:\n    def suggestedProducts(\n        self, products: List[str], searchWord: str\n    ) -> List[List[str]]:\n        products.sort()\n        trie = Trie()\n        for i, w in enumerate(products):\n            trie.insert(w, i)\n        return [[products[i] for i in v] for v in trie.search(searchWord)]",
    "sourceGoCode": "type Trie struct {\n\tchildren [26]*Trie\n\tv        []int\n}\n\nfunc newTrie() *Trie {\n\treturn &Trie{}\n}\nfunc (this *Trie) insert(w string, i int) {\n\tnode := this\n\tfor _, c := range w {\n\t\tc -= 'a'\n\t\tif node.children[c] == nil {\n\t\t\tnode.children[c] = newTrie()\n\t\t}\n\t\tnode = node.children[c]\n\t\tif len(node.v) < 3 {\n\t\t\tnode.v = append(node.v, i)\n\t\t}\n\t}\n}\n\nfunc (this *Trie) search(w string) [][]int {\n\tnode := this\n\tn := len(w)\n\tans := make([][]int, n)\n\tfor i, c := range w {\n\t\tc -= 'a'\n\t\tif node.children[c] == nil {\n\t\t\tbreak\n\t\t}\n\t\tnode = node.children[c]\n\t\tans[i] = node.v\n\t}\n\treturn ans\n}\n\nfunc suggestedProducts(products []string, searchWord string) (ans [][]string) {\n\tsort.Strings(products)\n\ttrie := newTrie()\n\tfor i, w := range products {\n\t\ttrie.insert(w, i)\n\t}\n\tfor _, v := range trie.search(searchWord) {\n\t\tt := []string{}\n\t\tfor _, i := range v {\n\t\t\tt = append(t, products[i])\n\t\t}\n\t\tans = append(ans, t)\n\t}\n\treturn\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 1268. Search Suggestions System.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nsearch_suggestions_system = solve\n\n\nif __name__ == \"__main__\":\n    print(\"1268. Search Suggestions System\")\n    print('Sample input:', \"products=[\\\"mobile\\\",\\\"mouse\\\",\\\"moneypot\\\",\\\"monitor\\\",\\\"mousepad\\\"], searchWord=\\\"mouse\\\"\")\n    print('Expected output:', \"[[\\\"mobile\\\",\\\"moneypot\\\",\\\"monitor\\\"],[\\\"mobile\\\",\\\"moneypot\\\",\\\"monitor\\\"],[\\\"mouse\\\",\\\"mousepad\\\"],[\\\"mouse\\\",\\\"mousepad\\\"],[\\\"mouse\\\",\\\"mousepad\\\"]]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
