    "leetcodeMainPath": "leetcode-main/solution/0900-0999/0901.Online Stock Span",
    "sourcePythonCode": "class StockSpanner:\n    def __init__(self):\n        self.stk = []\n\n    def next(self, price: int) -> int:\n        cnt = 1\n        while self.stk and self.stk[-1][0] <= price:\n            cnt += self.stk.pop()[1]\n        self.stk.append((price, cnt))\n        return cnt\n\n\n# Your StockSpanner object will be instantiated and called as such:\n# obj = StockSpanner()\n# param_1 = obj.next(price)",
    "sourceGoCode": "type StockSpanner struct {\n\tstk []pair\n}\n\nfunc Constructor() StockSpanner {\n\treturn StockSpanner{[]pair{}}\n}\n\nfunc (this *StockSpanner) Next(price int) int {\n\tcnt := 1\n\tfor len(this.stk) > 0 && this.stk[len(this.stk)-1].price <= price {\n\t\tcnt += this.stk[len(this.stk)-1].cnt\n\t\tthis.stk = this.stk[:len(this.stk)-1]\n\t}\n\tthis.stk = append(this.stk, pair{price, cnt})\n\treturn cnt\n}\n\ntype pair struct{ price, cnt int }\n\n/**\n * Your StockSpanner object will be instantiated and called as such:\n * obj := Constructor();\n * param_1 := obj.Next(price);\n */",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 901. Online Stock Span.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nonline_stock_span = solve\n\n\nif __name__ == \"__main__\":\n    print(\"901. Online Stock Span\")\n    print('Sample input:', \"prices=[100,80,60,70,60,75,85]\")\n    print('Expected output:', \"[1,1,1,2,1,4,6]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
