    "videoUrl": "https://www.youtube.com/results?search_query=LeetCode+68+Text+Justification+solution",
    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0068.Text Justification",
    "sourcePythonCode": "class Solution:\n    def fullJustify(self, words: List[str], maxWidth: int) -> List[str]:\n        ans = []\n        i, n = 0, len(words)\n        while i < n:\n            t = []\n            cnt = len(words[i])\n            t.append(words[i])\n            i += 1\n            while i < n and cnt + 1 + len(words[i]) <= maxWidth:\n                cnt += 1 + len(words[i])\n                t.append(words[i])\n                i += 1\n            if i == n or len(t) == 1:\n                left = ' '.join(t)\n                right = ' ' * (maxWidth - len(left))\n                ans.append(left + right)\n                continue\n            space_width = maxWidth - (cnt - len(t) + 1)\n            w, m = divmod(space_width, len(t) - 1)\n            row = []\n            for j, s in enumerate(t[:-1]):\n                row.append(s)\n                row.append(' ' * (w + (1 if j < m else 0)))\n            row.append(t[-1])\n            ans.append(''.join(row))\n        return ans",
    "sourceGoCode": "func fullJustify(words []string, maxWidth int) (ans []string) {\n\tfor i, n := 0, len(words); i < n; {\n\t\tt := []string{words[i]}\n\t\tcnt := len(words[i])\n\t\ti++\n\t\tfor i < n && cnt+1+len(words[i]) <= maxWidth {\n\t\t\tcnt += 1 + len(words[i])\n\t\t\tt = append(t, words[i])\n\t\t\ti++\n\t\t}\n\t\tif i == n || len(t) == 1 {\n\t\t\tleft := strings.Join(t, \" \")\n\t\t\tright := strings.Repeat(\" \", maxWidth-len(left))\n\t\t\tans = append(ans, left+right)\n\t\t\tcontinue\n\t\t}\n\t\tspaceWidth := maxWidth - (cnt - len(t) + 1)\n\t\tw := spaceWidth / (len(t) - 1)\n\t\tm := spaceWidth % (len(t) - 1)\n\t\trow := strings.Builder{}\n\t\tfor j, s := range t[:len(t)-1] {\n\t\t\trow.WriteString(s)\n\t\t\trow.WriteString(strings.Repeat(\" \", w))\n\t\t\tif j < m {\n\t\t\t\trow.WriteString(\" \")\n\t\t\t}\n\t\t}\n\t\trow.WriteString(t[len(t)-1])\n\t\tans = append(ans, row.String())\n\t}\n\treturn\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 68. Text Justification.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\ntext_justification = solve\n\n\nif __name__ == \"__main__\":\n    print(\"68. Text Justification\")\n    print('Sample input:', \"words=[\\\"This\\\",\\\"is\\\",\\\"an\\\",\\\"example\\\"], maxWidth=16\")\n    print('Expected output:', \"[\\\"This    is    an\\\",\\\"example         \\\"]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 68. Text Justification\nfunc Solve097(args ...any) any {\n\tanswer := make([]any, 0, len(args))\n\tanswer = append(answer, args...)\n\treturn answer\n}\n\nfunc main() {\n\tfmt.Println(\"68. Text Justification\")\n\tfmt.Println(\"Sample input:\", \"words=[\\\"This\\\",\\\"is\\\",\\\"an\\\",\\\"example\\\"], maxWidth=16\")\n\tfmt.Println(\"Expected output:\", \"[\\\"This    is    an\\\",\\\"example         \\\"]\")\n\tfmt.Println(\"Call Solve097(...) with parsed arguments for this problem.\")\n}\n"
