    "sourcePythonCode": "class Solution:\n    def lengthOfLongestSubstring(self, s: str) -> int:\n        cnt = Counter()\n        ans = l = 0\n        for r, c in enumerate(s):\n            cnt[c] += 1\n            while cnt[c] > 1:\n                cnt[s[l]] -= 1\n                l += 1\n            ans = max(ans, r - l + 1)\n        return ans",
