    "sourcePythonCode": "class Solution:\n    def canConstruct(self, ransomNote: str, magazine: str) -> bool:\n        cnt = Counter(magazine)\n        for c in ransomNote:\n            cnt[c] -= 1\n            if cnt[c] < 0:\n                return False\n        return True",
