    "sourcePythonCode": "class Solution:\n    def merge(self, intervals: List[List[int]]) -> List[List[int]]:\n        intervals.sort()\n        ans = []\n        st, ed = intervals[0]\n        for s, e in intervals[1:]:\n            if ed < s:\n                ans.append([st, ed])\n                st, ed = s, e\n            else:\n                ed = max(ed, e)\n        ans.append([st, ed])\n        return ans",
