    "leetcodeMainPath": "leetcode-main/solution/0100-0199/0155.Min Stack",
    "sourcePythonCode": "class MinStack:\n    def __init__(self):\n        self.stk1 = []\n        self.stk2 = [inf]\n\n    def push(self, val: int) -> None:\n        self.stk1.append(val)\n        self.stk2.append(min(val, self.stk2[-1]))\n\n    def pop(self) -> None:\n        self.stk1.pop()\n        self.stk2.pop()\n\n    def top(self) -> int:\n        return self.stk1[-1]\n\n    def getMin(self) -> int:\n        return self.stk2[-1]\n\n\n# Your MinStack object will be instantiated and called as such:\n# obj = MinStack()\n# obj.push(val)\n# obj.pop()\n# param_3 = obj.top()\n# param_4 = obj.getMin()",
    "sourceGoCode": "type MinStack struct {\n\tstk1 []int\n\tstk2 []int\n}\n\nfunc Constructor() MinStack {\n\treturn MinStack{[]int{}, []int{math.MaxInt32}}\n}\n\nfunc (this *MinStack) Push(val int) {\n\tthis.stk1 = append(this.stk1, val)\n\tthis.stk2 = append(this.stk2, min(val, this.stk2[len(this.stk2)-1]))\n}\n\nfunc (this *MinStack) Pop() {\n\tthis.stk1 = this.stk1[:len(this.stk1)-1]\n\tthis.stk2 = this.stk2[:len(this.stk2)-1]\n}\n\nfunc (this *MinStack) Top() int {\n\treturn this.stk1[len(this.stk1)-1]\n}\n\nfunc (this *MinStack) GetMin() int {\n\treturn this.stk2[len(this.stk2)-1]\n}\n\n/**\n * Your MinStack object will be instantiated and called as such:\n * obj := Constructor();\n * obj.Push(val);\n * obj.Pop();\n * param_3 := obj.Top();\n * param_4 := obj.GetMin();\n */",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 155. Min Stack.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    stack = []\n    for item in (args[0] if args else []):\n        stack.append(item)\n    return stack\n\n\n\nmin_stack = solve\n\n\nif __name__ == \"__main__\":\n    print(\"155. Min Stack\")\n    print('Sample input:', \"push(-2),push(0),push(-3),getMin,pop,top,getMin\")\n    print('Expected output:', \"[null,null,null,-3,null,0,-2]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
