    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0092.Reverse Linked List II",
    "sourcePythonCode": "# Definition for singly-linked list.\n# class ListNode:\n#     def __init__(self, val=0, next=None):\n#         self.val = val\n#         self.next = next\nclass Solution:\n    def reverseBetween(\n        self, head: Optional[ListNode], left: int, right: int\n    ) -> Optional[ListNode]:\n        if head.next is None or left == right:\n            return head\n        dummy = ListNode(0, head)\n        pre = dummy\n        for _ in range(left - 1):\n            pre = pre.next\n        p, q = pre, pre.next\n        cur = q\n        for _ in range(right - left + 1):\n            t = cur.next\n            cur.next = pre\n            pre, cur = cur, t\n        p.next = pre\n        q.next = cur\n        return dummy.next",
    "sourceGoCode": "/**\n * Definition for singly-linked list.\n * type ListNode struct {\n *     Val int\n *     Next *ListNode\n * }\n */\nfunc reverseBetween(head *ListNode, left int, right int) *ListNode {\n\tif head.Next == nil || left == right {\n\t\treturn head\n\t}\n\tdummy := &ListNode{0, head}\n\tpre := dummy\n\tfor i := 0; i < left-1; i++ {\n\t\tpre = pre.Next\n\t}\n\tp, q := pre, pre.Next\n\tcur := q\n\tfor i := 0; i < right-left+1; i++ {\n\t\tt := cur.Next\n\t\tcur.Next = pre\n\t\tpre = cur\n\t\tcur = t\n\t}\n\tp.Next = pre\n\tq.Next = cur\n\treturn dummy.Next\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 92. Reverse Linked List II.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nreverse_linked_list_ii = solve\n\n\nif __name__ == \"__main__\":\n    print(\"92. Reverse Linked List II\")\n    print('Sample input:', \"head=[1,2,3,4,5], left=2, right=4\")\n    print('Expected output:', \"[1,4,3,2,5]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
