    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0025.Reverse Nodes in k-Group",
    "sourcePythonCode": "# Definition for singly-linked list.\n# class ListNode:\n#     def __init__(self, val=0, next=None):\n#         self.val = val\n#         self.next = next\nclass Solution:\n    def reverseKGroup(self, head: Optional[ListNode], k: int) -> Optional[ListNode]:\n        def reverse(head: Optional[ListNode]) -> Optional[ListNode]:\n            dummy = ListNode()\n            cur = head\n            while cur:\n                nxt = cur.next\n                cur.next = dummy.next\n                dummy.next = cur\n                cur = nxt\n            return dummy.next\n\n        dummy = pre = ListNode(next=head)\n        while pre:\n            cur = pre\n            for _ in range(k):\n                cur = cur.next\n                if cur is None:\n                    return dummy.next\n            node = pre.next\n            nxt = cur.next\n            cur.next = None\n            pre.next = reverse(node)\n            node.next = nxt\n            pre = node\n        return dummy.next",
    "sourceGoCode": "/**\n * Definition for singly-linked list.\n * type ListNode struct {\n *     Val int\n *     Next *ListNode\n * }\n */\nfunc reverseKGroup(head *ListNode, k int) *ListNode {\n\tdummy := &ListNode{Next: head}\n\tpre := dummy\n\n\tfor pre != nil {\n\t\tcur := pre\n\t\tfor i := 0; i < k; i++ {\n\t\t\tcur = cur.Next\n\t\t\tif cur == nil {\n\t\t\t\treturn dummy.Next\n\t\t\t}\n\t\t}\n\n\t\tnode := pre.Next\n\t\tnxt := cur.Next\n\t\tcur.Next = nil\n\t\tpre.Next = reverse(node)\n\t\tnode.Next = nxt\n\t\tpre = node\n\t}\n\treturn dummy.Next\n}\n\nfunc reverse(head *ListNode) *ListNode {\n\tvar dummy *ListNode\n\tcur := head\n\tfor cur != nil {\n\t\tnxt := cur.Next\n\t\tcur.Next = dummy\n\t\tdummy = cur\n\t\tcur = nxt\n\t}\n\treturn dummy\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 25. Reverse Nodes in k-Group.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nreverse_nodes_in_k_group = solve\n\n\nif __name__ == \"__main__\":\n    print(\"25. Reverse Nodes in k-Group\")\n    print('Sample input:', \"head=[1,2,3,4,5], k=2\")\n    print('Expected output:', \"[2,1,4,3,5]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
