    "videoUrl": "https://www.youtube.com/results?search_query=LeetCode+61+Rotate+List+solution",
    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0061.Rotate List",
    "sourcePythonCode": "# Definition for singly-linked list.\n# class ListNode:\n#     def __init__(self, val=0, next=None):\n#         self.val = val\n#         self.next = next\nclass Solution:\n    def rotateRight(self, head: Optional[ListNode], k: int) -> Optional[ListNode]:\n        if head is None or head.next is None:\n            return head\n        cur, n = head, 0\n        while cur:\n            n += 1\n            cur = cur.next\n        k %= n\n        if k == 0:\n            return head\n        fast = slow = head\n        for _ in range(k):\n            fast = fast.next\n        while fast.next:\n            fast, slow = fast.next, slow.next\n\n        ans = slow.next\n        slow.next = None\n        fast.next = head\n        return ans",
    "sourceGoCode": "/**\n * Definition for singly-linked list.\n * type ListNode struct {\n *     Val int\n *     Next *ListNode\n * }\n */\nfunc rotateRight(head *ListNode, k int) *ListNode {\n\tif head == nil || head.Next == nil {\n\t\treturn head\n\t}\n\tcur := head\n\tn := 0\n\tfor cur != nil {\n\t\tcur = cur.Next\n\t\tn++\n\t}\n\tk %= n\n\tif k == 0 {\n\t\treturn head\n\t}\n\tfast, slow := head, head\n\tfor i := 0; i < k; i++ {\n\t\tfast = fast.Next\n\t}\n\tfor fast.Next != nil {\n\t\tfast = fast.Next\n\t\tslow = slow.Next\n\t}\n\tans := slow.Next\n\tslow.Next = nil\n\tfast.Next = head\n\treturn ans\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 61. Rotate List.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nrotate_list = solve\n\n\nif __name__ == \"__main__\":\n    print(\"61. Rotate List\")\n    print('Sample input:', \"head=[1,2,3,4,5], k=2\")\n    print('Expected output:', \"[4,5,1,2,3]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 61. Rotate List\nfunc Solve135(args ...any) any {\n\tanswer := make([]any, 0, len(args))\n\tanswer = append(answer, args...)\n\treturn answer\n}\n\nfunc main() {\n\tfmt.Println(\"61. Rotate List\")\n\tfmt.Println(\"Sample input:\", \"head=[1,2,3,4,5], k=2\")\n\tfmt.Println(\"Expected output:\", \"[4,5,1,2,3]\")\n\tfmt.Println(\"Call Solve135(...) with parsed arguments for this problem.\")\n}\n"
