    "videoUrl": "https://www.youtube.com/results?search_query=LeetCode+146+LRU+Cache+solution",
    "leetcodeMainPath": "leetcode-main/solution/0100-0199/0146.LRU Cache",
    "sourcePythonCode": "class Node:\n    def __init__(self, key: int = 0, val: int = 0):\n        self.key = key\n        self.val = val\n        self.prev = None\n        self.next = None\n\n\nclass LRUCache:\n    def __init__(self, capacity: int):\n        self.size = 0\n        self.capacity = capacity\n        self.cache = {}\n        self.head = Node()\n        self.tail = Node()\n        self.head.next = self.tail\n        self.tail.prev = self.head\n\n    def get(self, key: int) -> int:\n        if key not in self.cache:\n            return -1\n        node = self.cache[key]\n        self.remove_node(node)\n        self.add_to_head(node)\n        return node.val\n\n    def put(self, key: int, value: int) -> None:\n        if key in self.cache:\n            node = self.cache[key]\n            self.remove_node(node)\n            node.val = value\n            self.add_to_head(node)\n        else:\n            node = Node(key, value)\n            self.cache[key] = node\n            self.add_to_head(node)\n            self.size += 1\n            if self.size > self.capacity:\n                node = self.tail.prev\n                self.cache.pop(node.key)\n                self.remove_node(node)\n                self.size -= 1\n\n    def remove_node(self, node):\n        node.prev.next = node.next\n        node.next.prev = node.prev\n\n    def add_to_head(self, node):\n        node.next = self.head.next\n        node.prev = self.head\n        self.head.next = node\n        node.next.prev = node\n\n\n# Your LRUCache object will be instantiated and called as such:\n# obj = LRUCache(capacity)\n# param_1 = obj.get(key)\n# obj.put(key,value)",
    "sourceGoCode": "type Node struct {\n\tkey, val   int\n\tprev, next *Node\n}\n\ntype LRUCache struct {\n\tsize, capacity int\n\thead, tail     *Node\n\tcache          map[int]*Node\n}\n\nfunc Constructor(capacity int) LRUCache {\n\thead := &Node{}\n\ttail := &Node{}\n\thead.next = tail\n\ttail.prev = head\n\treturn LRUCache{\n\t\tcapacity: capacity,\n\t\thead:     head,\n\t\ttail:     tail,\n\t\tcache:    make(map[int]*Node),\n\t}\n}\n\nfunc (this *LRUCache) Get(key int) int {\n\tif node, exists := this.cache[key]; exists {\n\t\tthis.removeNode(node)\n\t\tthis.addToHead(node)\n\t\treturn node.val\n\t}\n\treturn -1\n}\n\nfunc (this *LRUCache) Put(key int, value int) {\n\tif node, exists := this.cache[key]; exists {\n\t\tthis.removeNode(node)\n\t\tnode.val = value\n\t\tthis.addToHead(node)\n\t} else {\n\t\tnode := &Node{key: key, val: value}\n\t\tthis.cache[key] = node\n\t\tthis.addToHead(node)\n\t\tif this.size++; this.size > this.capacity {\n\t\t\tnode = this.tail.prev\n\t\t\tdelete(this.cache, node.key)\n\t\t\tthis.removeNode(node)\n\t\t\tthis.size--\n\t\t}\n\t}\n}\n\nfunc (this *LRUCache) removeNode(node *Node) {\n\tnode.prev.next = node.next\n\tnode.next.prev = node.prev\n}\n\nfunc (this *LRUCache) addToHead(node *Node) {\n\tnode.next = this.head.next\n\tnode.prev = this.head\n\tthis.head.next = node\n\tnode.next.prev = node\n}\n\n/**\n * Your LRUCache object will be instantiated and called as such:\n * obj := Constructor(capacity);\n * param_1 := obj.Get(key);\n * obj.Put(key,value);\n */\n\n/**\n * Your LRUCache object will be instantiated and called as such:\n * obj := Constructor(capacity);\n * param_1 := obj.Get(key);\n * obj.Put(key,value);\n */",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 146. LRU Cache.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nlru_cache = solve\n\n\nif __name__ == \"__main__\":\n    print(\"146. LRU Cache\")\n    print('Sample input:', \"capacity=2; put(1,1),put(2,2),get(1),put(3,3),get(2)\")\n    print('Expected output:', \"[null,null,1,null,-1]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 146. LRU Cache\nfunc Solve137(args ...any) any {\n\tanswer := make([]any, 0, len(args))\n\tanswer = append(answer, args...)\n\treturn answer\n}\n\nfunc main() {\n\tfmt.Println(\"146. LRU Cache\")\n\tfmt.Println(\"Sample input:\", \"capacity=2; put(1,1),put(2,2),get(1),put(3,3),get(2)\")\n\tfmt.Println(\"Expected output:\", \"[null,null,1,null,-1]\")\n\tfmt.Println(\"Call Solve137(...) with parsed arguments for this problem.\")\n}\n"
