    "leetcodeMainPath": "leetcode-main/solution/0100-0199/0173.Binary Search Tree Iterator",
    "sourcePythonCode": "# Definition for a binary tree node.\n# class TreeNode:\n#     def __init__(self, val=0, left=None, right=None):\n#         self.val = val\n#         self.left = left\n#         self.right = right\nclass BSTIterator:\n    def __init__(self, root: TreeNode):\n        def inorder(root):\n            if root:\n                inorder(root.left)\n                self.vals.append(root.val)\n                inorder(root.right)\n\n        self.cur = 0\n        self.vals = []\n        inorder(root)\n\n    def next(self) -> int:\n        res = self.vals[self.cur]\n        self.cur += 1\n        return res\n\n    def hasNext(self) -> bool:\n        return self.cur < len(self.vals)\n\n\n# Your BSTIterator object will be instantiated and called as such:\n# obj = BSTIterator(root)\n# param_1 = obj.next()\n# param_2 = obj.hasNext()",
    "sourceGoCode": "/**\n * Definition for a binary tree node.\n * type TreeNode struct {\n *     Val int\n *     Left *TreeNode\n *     Right *TreeNode\n * }\n */\ntype BSTIterator struct {\n\tstack []*TreeNode\n}\n\nfunc Constructor(root *TreeNode) BSTIterator {\n\tvar stack []*TreeNode\n\tfor ; root != nil; root = root.Left {\n\t\tstack = append(stack, root)\n\t}\n\treturn BSTIterator{\n\t\tstack: stack,\n\t}\n}\n\nfunc (this *BSTIterator) Next() int {\n\tcur := this.stack[len(this.stack)-1]\n\tthis.stack = this.stack[:len(this.stack)-1]\n\tfor node := cur.Right; node != nil; node = node.Left {\n\t\tthis.stack = append(this.stack, node)\n\t}\n\treturn cur.Val\n}\n\nfunc (this *BSTIterator) HasNext() bool {\n\treturn len(this.stack) > 0\n}\n\n/**\n * Your BSTIterator object will be instantiated and called as such:\n * obj := Constructor(root);\n * param_1 := obj.Next();\n * param_2 := obj.HasNext();\n */",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 173. Binary Search Tree Iterator.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nbinary_search_tree_iterator = solve\n\n\nif __name__ == \"__main__\":\n    print(\"173. Binary Search Tree Iterator\")\n    print('Sample input:', \"BST=[7,3,15,null,null,9,20], calls=next,next,hasNext\")\n    print('Expected output:', \"[3,7,true]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 173. Binary Search Tree Iterator\nfunc Solve148(args ...any) any {\n\tanswer := make([]any, 0, len(args))\n\tanswer = append(answer, args...)\n\treturn answer\n}\n\nfunc main() {\n\tfmt.Println(\"173. Binary Search Tree Iterator\")\n\tfmt.Println(\"Sample input:\", \"BST=[7,3,15,null,null,9,20], calls=next,next,hasNext\")\n\tfmt.Println(\"Expected output:\", \"[3,7,true]\")\n\tfmt.Println(\"Call Solve148(...) with parsed arguments for this problem.\")\n}\n"
