    "sourceGoCode": "/**\n * Definition for a binary tree node.\n * type TreeNode struct {\n *     Val int\n *     Left *TreeNode\n *     Right *TreeNode\n * }\n */\nfunc averageOfLevels(root *TreeNode) []float64 {\n\tq := []*TreeNode{root}\n\tans := []float64{}\n\tfor len(q) > 0 {\n\t\tn := len(q)\n\t\ts := 0\n\t\tfor i := 0; i < n; i++ {\n\t\t\troot = q[0]\n\t\t\tq = q[1:]\n\t\t\ts += root.Val\n\t\t\tif root.Left != nil {\n\t\t\t\tq = append(q, root.Left)\n\t\t\t}\n\t\t\tif root.Right != nil {\n\t\t\t\tq = append(q, root.Right)\n\t\t\t}\n\t\t}\n\t\tans = append(ans, float64(s)/float64(n))\n\t}\n\treturn ans\n}",
