    "sourcePythonCode": "# Definition for a binary tree node.\n# class TreeNode:\n#     def __init__(self, val=0, left=None, right=None):\n#         self.val = val\n#         self.left = left\n#         self.right = right\nclass Solution:\n    def getMinimumDifference(self, root: Optional[TreeNode]) -> int:\n        def dfs(root: Optional[TreeNode]):\n            if root is None:\n                return\n            dfs(root.left)\n            nonlocal pre, ans\n            ans = min(ans, root.val - pre)\n            pre = root.val\n            dfs(root.right)\n\n        pre = -inf\n        ans = inf\n        dfs(root)\n        return ans",
