    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0098.Validate Binary Search Tree",
    "sourcePythonCode": "# Definition for a binary tree node.\n# class TreeNode:\n#     def __init__(self, val=0, left=None, right=None):\n#         self.val = val\n#         self.left = left\n#         self.right = right\nclass Solution:\n    def isValidBST(self, root: Optional[TreeNode]) -> bool:\n        def dfs(root: Optional[TreeNode]) -> bool:\n            if root is None:\n                return True\n            if not dfs(root.left):\n                return False\n            nonlocal prev\n            if prev >= root.val:\n                return False\n            prev = root.val\n            return dfs(root.right)\n\n        prev = -inf\n        return dfs(root)",
    "sourceGoCode": "/**\n * Definition for a binary tree node.\n * type TreeNode struct {\n *     Val int\n *     Left *TreeNode\n *     Right *TreeNode\n * }\n */\nfunc isValidBST(root *TreeNode) bool {\n\tvar prev *TreeNode\n\tvar dfs func(*TreeNode) bool\n\tdfs = func(root *TreeNode) bool {\n\t\tif root == nil {\n\t\t\treturn true\n\t\t}\n\t\tif !dfs(root.Left) {\n\t\t\treturn false\n\t\t}\n\t\tif prev != nil && prev.Val >= root.Val {\n\t\t\treturn false\n\t\t}\n\t\tprev = root\n\t\treturn dfs(root.Right)\n\t}\n\treturn dfs(root)\n}",
