    "sourcePythonCode": "class Solution:\n    def numIslands(self, grid: List[List[str]]) -> int:\n        def dfs(i, j):\n            grid[i][j] = '0'\n            for a, b in pairwise(dirs):\n                x, y = i + a, j + b\n                if 0 <= x < m and 0 <= y < n and grid[x][y] == '1':\n                    dfs(x, y)\n\n        ans = 0\n        dirs = (-1, 0, 1, 0, -1)\n        m, n = len(grid), len(grid[0])\n        for i in range(m):\n            for j in range(n):\n                if grid[i][j] == '1':\n                    dfs(i, j)\n                    ans += 1\n        return ans",
    "sourceGoCode": "func numIslands(grid [][]byte) int {\n\tm, n := len(grid), len(grid[0])\n\tvar dfs func(i, j int)\n\tdfs = func(i, j int) {\n\t\tgrid[i][j] = '0'\n\t\tdirs := []int{-1, 0, 1, 0, -1}\n\t\tfor k := 0; k < 4; k++ {\n\t\t\tx, y := i+dirs[k], j+dirs[k+1]\n\t\t\tif x >= 0 && x < m && y >= 0 && y < n && grid[x][y] == '1' {\n\t\t\t\tdfs(x, y)\n\t\t\t}\n\t\t}\n\t}\n\tans := 0\n\tfor i := 0; i < m; i++ {\n\t\tfor j := 0; j < n; j++ {\n\t\t\tif grid[i][j] == '1' {\n\t\t\t\tdfs(i, j)\n\t\t\t\tans++\n\t\t\t}\n\t\t}\n\t}\n\treturn ans\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 200. Number of Islands.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    graph = {}\n    for a, b in (args[1] if len(args) > 1 else []):\n        graph.setdefault(a, []).append(b)\n        graph.setdefault(b, []).append(a)\n    return graph\n\n\n\nnumber_of_islands = solve\n\n\nif __name__ == \"__main__\":\n    print(\"200. Number of Islands\")\n    print('Sample input:', \"grid=[[\\\"1\\\",\\\"1\\\",\\\"0\\\"],[\\\"0\\\",\\\"1\\\",\\\"0\\\"],[\\\"1\\\",\\\"0\\\",\\\"1\\\"]]\")\n    print('Expected output:', \"3\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
