    "leetcodeMainPath": "leetcode-main/solution/0200-0299/0211.Design Add and Search Words Data Structure",
    "sourcePythonCode": "class Trie:\n    def __init__(self):\n        self.children = [None] * 26\n        self.is_end = False\n\n\nclass WordDictionary:\n    def __init__(self):\n        self.trie = Trie()\n\n    def addWord(self, word: str) -> None:\n        node = self.trie\n        for c in word:\n            idx = ord(c) - ord('a')\n            if node.children[idx] is None:\n                node.children[idx] = Trie()\n            node = node.children[idx]\n        node.is_end = True\n\n    def search(self, word: str) -> bool:\n        def search(word, node):\n            for i in range(len(word)):\n                c = word[i]\n                idx = ord(c) - ord('a')\n                if c != '.' and node.children[idx] is None:\n                    return False\n                if c == '.':\n                    for child in node.children:\n                        if child is not None and search(word[i + 1 :], child):\n                            return True\n                    return False\n                node = node.children[idx]\n            return node.is_end\n\n        return search(word, self.trie)\n\n\n# Your WordDictionary object will be instantiated and called as such:\n# obj = WordDictionary()\n# obj.addWord(word)\n# param_2 = obj.search(word)",
    "sourceGoCode": "type WordDictionary struct {\n\troot *trie\n}\n\nfunc Constructor() WordDictionary {\n\treturn WordDictionary{new(trie)}\n}\n\nfunc (this *WordDictionary) AddWord(word string) {\n\tthis.root.insert(word)\n}\n\nfunc (this *WordDictionary) Search(word string) bool {\n\tn := len(word)\n\n\tvar dfs func(int, *trie) bool\n\tdfs = func(i int, cur *trie) bool {\n\t\tif i == n {\n\t\t\treturn cur.isEnd\n\t\t}\n\t\tc := word[i]\n\t\tif c != '.' {\n\t\t\tchild := cur.children[c-'a']\n\t\t\tif child != nil && dfs(i+1, child) {\n\t\t\t\treturn true\n\t\t\t}\n\t\t} else {\n\t\t\tfor _, child := range cur.children {\n\t\t\t\tif child != nil && dfs(i+1, child) {\n\t\t\t\t\treturn true\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t\treturn false\n\t}\n\n\treturn dfs(0, this.root)\n}\n\ntype trie struct {\n\tchildren [26]*trie\n\tisEnd    bool\n}\n\nfunc (t *trie) insert(word string) {\n\tcur := t\n\tfor _, c := range word {\n\t\tc -= 'a'\n\t\tif cur.children[c] == nil {\n\t\t\tcur.children[c] = new(trie)\n\t\t}\n\t\tcur = cur.children[c]\n\t}\n\tcur.isEnd = true\n}\n\n/**\n * Your WordDictionary object will be instantiated and called as such:\n * obj := Constructor();\n * obj.AddWord(word);\n * param_2 := obj.Search(word);\n */",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 211. Design Add and Search Words Data Structure.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\ndesign_add_and_search_words_data_structure = solve\n\n\nif __name__ == \"__main__\":\n    print(\"211. Design Add and Search Words Data Structure\")\n    print('Sample input:', \"add bad,dad,mad; search pad,bad,.ad,b..\")\n    print('Expected output:', \"[false,true,true,true]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
