    "leetcodeMainPath": "leetcode-main/solution/0200-0299/0212.Word Search II",
    "sourcePythonCode": "class Trie:\n    def __init__(self):\n        self.children: List[Trie | None] = [None] * 26\n        self.ref: int = -1\n\n    def insert(self, w: str, ref: int):\n        node = self\n        for c in w:\n            idx = ord(c) - ord('a')\n            if node.children[idx] is None:\n                node.children[idx] = Trie()\n            node = node.children[idx]\n        node.ref = ref\n\n\nclass Solution:\n    def findWords(self, board: List[List[str]], words: List[str]) -> List[str]:\n        def dfs(node: Trie, i: int, j: int):\n            idx = ord(board[i][j]) - ord('a')\n            if node.children[idx] is None:\n                return\n            node = node.children[idx]\n            if node.ref >= 0:\n                ans.append(words[node.ref])\n                node.ref = -1\n            c = board[i][j]\n            board[i][j] = '#'\n            for a, b in pairwise((-1, 0, 1, 0, -1)):\n                x, y = i + a, j + b\n                if 0 <= x < m and 0 <= y < n and board[x][y] != '#':\n                    dfs(node, x, y)\n            board[i][j] = c\n\n        tree = Trie()\n        for i, w in enumerate(words):\n            tree.insert(w, i)\n        m, n = len(board), len(board[0])\n        ans = []\n        for i in range(m):\n            for j in range(n):\n                dfs(tree, i, j)\n        return ans",
    "sourceGoCode": "type Trie struct {\n\tchildren [26]*Trie\n\tref      int\n}\n\nfunc newTrie() *Trie {\n\treturn &Trie{ref: -1}\n}\nfunc (this *Trie) insert(w string, ref int) {\n\tnode := this\n\tfor _, c := range w {\n\t\tc -= 'a'\n\t\tif node.children[c] == nil {\n\t\t\tnode.children[c] = newTrie()\n\t\t}\n\t\tnode = node.children[c]\n\t}\n\tnode.ref = ref\n}\n\nfunc findWords(board [][]byte, words []string) (ans []string) {\n\ttrie := newTrie()\n\tfor i, w := range words {\n\t\ttrie.insert(w, i)\n\t}\n\tm, n := len(board), len(board[0])\n\tvar dfs func(*Trie, int, int)\n\tdfs = func(node *Trie, i, j int) {\n\t\tidx := board[i][j] - 'a'\n\t\tif node.children[idx] == nil {\n\t\t\treturn\n\t\t}\n\t\tnode = node.children[idx]\n\t\tif node.ref != -1 {\n\t\t\tans = append(ans, words[node.ref])\n\t\t\tnode.ref = -1\n\t\t}\n\t\tc := board[i][j]\n\t\tboard[i][j] = '#'\n\t\tdirs := [5]int{-1, 0, 1, 0, -1}\n\t\tfor k := 0; k < 4; k++ {\n\t\t\tx, y := i+dirs[k], j+dirs[k+1]\n\t\t\tif x >= 0 && x < m && y >= 0 && y < n && board[x][y] != '#' {\n\t\t\t\tdfs(node, x, y)\n\t\t\t}\n\t\t}\n\t\tboard[i][j] = c\n\t}\n\tfor i := 0; i < m; i++ {\n\t\tfor j := 0; j < n; j++ {\n\t\t\tdfs(trie, i, j)\n\t\t}\n\t}\n\treturn\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 212. Word Search II.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nword_search_ii = solve\n\n\nif __name__ == \"__main__\":\n    print(\"212. Word Search II\")\n    print('Sample input:', \"board=[[\\\"o\\\",\\\"a\\\",\\\"a\\\",\\\"n\\\"],[\\\"e\\\",\\\"t\\\",\\\"a\\\",\\\"e\\\"],[\\\"i\\\",\\\"h\\\",\\\"k\\\",\\\"r\\\"],[\\\"i\\\",\\\"f\\\",\\\"l\\\",\\\"v\\\"]], words=[\\\"oath\\\",\\\"pea\\\",\\\"eat\\\",\\\"rain\\\"]\")\n    print('Expected output:', \"[\\\"eat\\\",\\\"oath\\\"]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
