    "sourcePythonCode": "class Solution:\n    def combine(self, n: int, k: int) -> List[List[int]]:\n        def dfs(i: int):\n            if len(t) == k:\n                ans.append(t[:])\n                return\n            if i > n:\n                return\n            t.append(i)\n            dfs(i + 1)\n            t.pop()\n            dfs(i + 1)\n\n        ans = []\n        t = []\n        dfs(1)\n        return ans",
