    "sourcePythonCode": "class Solution:\n    def combinationSum(self, candidates: List[int], target: int) -> List[List[int]]:\n        def dfs(i: int, s: int):\n            if s == 0:\n                ans.append(t[:])\n                return\n            if s < candidates[i]:\n                return\n            for j in range(i, len(candidates)):\n                t.append(candidates[j])\n                dfs(j, s - candidates[j])\n                t.pop()\n\n        candidates.sort()\n        t = []\n        ans = []\n        dfs(0, target)\n        return ans",
