    "sourcePythonCode": "class Solution:\n    def generateParenthesis(self, n: int) -> List[str]:\n        def dfs(l: int, r: int, t: str):\n            if l > n or r > n or l < r:\n                return\n            if l == n and r == n:\n                ans.append(t)\n                return\n            dfs(l + 1, r, t + \"(\")\n            dfs(l, r + 1, t + \")\")\n\n        ans = []\n        dfs(0, 0, \"\")\n        return ans",
