    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0079.Word Search",
    "sourcePythonCode": "class Solution:\n    def exist(self, board: List[List[str]], word: str) -> bool:\n        def dfs(i: int, j: int, k: int) -> bool:\n            if k == len(word) - 1:\n                return board[i][j] == word[k]\n            if board[i][j] != word[k]:\n                return False\n            c = board[i][j]\n            board[i][j] = \"0\"\n            for a, b in pairwise((-1, 0, 1, 0, -1)):\n                x, y = i + a, j + b\n                ok = 0 <= x < m and 0 <= y < n and board[x][y] != \"0\"\n                if ok and dfs(x, y, k + 1):\n                    return True\n            board[i][j] = c\n            return False\n\n        m, n = len(board), len(board[0])\n        return any(dfs(i, j, 0) for i in range(m) for j in range(n))",
    "sourceGoCode": "func exist(board [][]byte, word string) bool {\n\tm, n := len(board), len(board[0])\n\tvar dfs func(int, int, int) bool\n\tdfs = func(i, j, k int) bool {\n\t\tif k == len(word)-1 {\n\t\t\treturn board[i][j] == word[k]\n\t\t}\n\t\tif board[i][j] != word[k] {\n\t\t\treturn false\n\t\t}\n\t\tdirs := [5]int{-1, 0, 1, 0, -1}\n\t\tc := board[i][j]\n\t\tboard[i][j] = '0'\n\t\tfor u := 0; u < 4; u++ {\n\t\t\tx, y := i+dirs[u], j+dirs[u+1]\n\t\t\tif x >= 0 && x < m && y >= 0 && y < n && board[x][y] != '0' && dfs(x, y, k+1) {\n\t\t\t\treturn true\n\t\t\t}\n\t\t}\n\t\tboard[i][j] = c\n\t\treturn false\n\t}\n\tfor i := 0; i < m; i++ {\n\t\tfor j := 0; j < n; j++ {\n\t\t\tif dfs(i, j, 0) {\n\t\t\t\treturn true\n\t\t\t}\n\t\t}\n\t}\n\treturn false\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 79. Word Search.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nword_search = solve\n\n\nif __name__ == \"__main__\":\n    print(\"79. Word Search\")\n    print('Sample input:', \"board=[[\\\"A\\\",\\\"B\\\",\\\"C\\\",\\\"E\\\"],[\\\"S\\\",\\\"F\\\",\\\"C\\\",\\\"S\\\"],[\\\"A\\\",\\\"D\\\",\\\"E\\\",\\\"E\\\"]], word=\\\"ABCCED\\\"\")\n    print('Expected output:', \"true\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 79. Word Search\nfunc Solve171(args ...any) any {\n\tanswer := make([]any, 0, len(args))\n\tanswer = append(answer, args...)\n\treturn answer\n}\n\nfunc main() {\n\tfmt.Println(\"79. Word Search\")\n\tfmt.Println(\"Sample input:\", \"board=[[\\\"A\\\",\\\"B\\\",\\\"C\\\",\\\"E\\\"],[\\\"S\\\",\\\"F\\\",\\\"C\\\",\\\"S\\\"],[\\\"A\\\",\\\"D\\\",\\\"E\\\",\\\"E\\\"]], word=\\\"ABCCED\\\"\")\n\tfmt.Println(\"Expected output:\", \"true\")\n\tfmt.Println(\"Call Solve171(...) with parsed arguments for this problem.\")\n}\n"
