    "videoUrl": "https://www.youtube.com/results?search_query=LeetCode+148+Sort+List+solution",
    "leetcodeMainPath": "leetcode-main/solution/0100-0199/0148.Sort List",
    "sourcePythonCode": "# Definition for singly-linked list.\n# class ListNode:\n#     def __init__(self, val=0, next=None):\n#         self.val = val\n#         self.next = next\nclass Solution:\n    def sortList(self, head: Optional[ListNode]) -> Optional[ListNode]:\n        if head is None or head.next is None:\n            return head\n        slow, fast = head, head.next\n        while fast and fast.next:\n            slow = slow.next\n            fast = fast.next.next\n        l1, l2 = head, slow.next\n        slow.next = None\n        l1, l2 = self.sortList(l1), self.sortList(l2)\n        dummy = ListNode()\n        tail = dummy\n        while l1 and l2:\n            if l1.val <= l2.val:\n                tail.next = l1\n                l1 = l1.next\n            else:\n                tail.next = l2\n                l2 = l2.next\n            tail = tail.next\n        tail.next = l1 or l2\n        return dummy.next",
    "sourceGoCode": "/**\n * Definition for singly-linked list.\n * type ListNode struct {\n *     Val int\n *     Next *ListNode\n * }\n */\nfunc sortList(head *ListNode) *ListNode {\n\tif head == nil || head.Next == nil {\n\t\treturn head\n\t}\n\tslow, fast := head, head.Next\n\tfor fast != nil && fast.Next != nil {\n\t\tslow, fast = slow.Next, fast.Next.Next\n\t}\n\tl1 := head\n\tl2 := slow.Next\n\tslow.Next = nil\n\tl1 = sortList(l1)\n\tl2 = sortList(l2)\n\tdummy := &ListNode{}\n\ttail := dummy\n\tfor l1 != nil && l2 != nil {\n\t\tif l1.Val <= l2.Val {\n\t\t\ttail.Next = l1\n\t\t\tl1 = l1.Next\n\t\t} else {\n\t\t\ttail.Next = l2\n\t\t\tl2 = l2.Next\n\t\t}\n\t\ttail = tail.Next\n\t}\n\tif l1 != nil {\n\t\ttail.Next = l1\n\t} else {\n\t\ttail.Next = l2\n\t}\n\treturn dummy.Next\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 148. Sort List.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nsort_list = solve\n\n\nif __name__ == \"__main__\":\n    print(\"148. Sort List\")\n    print('Sample input:', \"head=[4,2,1,3]\")\n    print('Expected output:', \"[1,2,3,4]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 148. Sort List\nfunc Solve173(args ...any) any {\n\tanswer := make([]any, 0, len(args))\n\tanswer = append(answer, args...)\n\treturn answer\n}\n\nfunc main() {\n\tfmt.Println(\"148. Sort List\")\n\tfmt.Println(\"Sample input:\", \"head=[4,2,1,3]\")\n\tfmt.Println(\"Expected output:\", \"[1,2,3,4]\")\n\tfmt.Println(\"Call Solve173(...) with parsed arguments for this problem.\")\n}\n"
