    "videoUrl": "https://www.youtube.com/results?search_query=LeetCode+427+Construct+Quad+Tree+solution",
    "leetcodeMainPath": "leetcode-main/solution/0400-0499/0427.Construct Quad Tree",
    "sourcePythonCode": "\"\"\"\n# Definition for a QuadTree node.\nclass Node:\n    def __init__(self, val, isLeaf, topLeft, topRight, bottomLeft, bottomRight):\n        self.val = val\n        self.isLeaf = isLeaf\n        self.topLeft = topLeft\n        self.topRight = topRight\n        self.bottomLeft = bottomLeft\n        self.bottomRight = bottomRight\n\"\"\"\n\n\nclass Solution:\n    def construct(self, grid: List[List[int]]) -> 'Node':\n        def dfs(a, b, c, d):\n            zero = one = 0\n            for i in range(a, c + 1):\n                for j in range(b, d + 1):\n                    if grid[i][j] == 0:\n                        zero = 1\n                    else:\n                        one = 1\n            isLeaf = zero + one == 1\n            val = isLeaf and one\n            if isLeaf:\n                return Node(grid[a][b], True)\n            topLeft = dfs(a, b, (a + c) // 2, (b + d) // 2)\n            topRight = dfs(a, (b + d) // 2 + 1, (a + c) // 2, d)\n            bottomLeft = dfs((a + c) // 2 + 1, b, c, (b + d) // 2)\n            bottomRight = dfs((a + c) // 2 + 1, (b + d) // 2 + 1, c, d)\n            return Node(val, isLeaf, topLeft, topRight, bottomLeft, bottomRight)\n\n        return dfs(0, 0, len(grid) - 1, len(grid[0]) - 1)",
    "sourceGoCode": "/**\n * Definition for a QuadTree node.\n * type Node struct {\n *     Val bool\n *     IsLeaf bool\n *     TopLeft *Node\n *     TopRight *Node\n *     BottomLeft *Node\n *     BottomRight *Node\n * }\n */\n\nfunc construct(grid [][]int) *Node {\n\tvar dfs func(a, b, c, d int) *Node\n\tdfs = func(a, b, c, d int) *Node {\n\t\tzero, one := 0, 0\n\t\tfor i := a; i <= c; i++ {\n\t\t\tfor j := b; j <= d; j++ {\n\t\t\t\tif grid[i][j] == 0 {\n\t\t\t\t\tzero = 1\n\t\t\t\t} else {\n\t\t\t\t\tone = 1\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t\tisLeaf := zero+one == 1\n\t\tval := isLeaf && one == 1\n\t\tnode := &Node{Val: val, IsLeaf: isLeaf}\n\t\tif isLeaf {\n\t\t\treturn node\n\t\t}\n\t\tnode.TopLeft = dfs(a, b, (a+c)/2, (b+d)/2)\n\t\tnode.TopRight = dfs(a, (b+d)/2+1, (a+c)/2, d)\n\t\tnode.BottomLeft = dfs((a+c)/2+1, b, c, (b+d)/2)\n\t\tnode.BottomRight = dfs((a+c)/2+1, (b+d)/2+1, c, d)\n\t\treturn node\n\t}\n\treturn dfs(0, 0, len(grid)-1, len(grid[0])-1)\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 427. Construct Quad Tree.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nconstruct_quad_tree = solve\n\n\nif __name__ == \"__main__\":\n    print(\"427. Construct Quad Tree\")\n    print('Sample input:', \"grid=[[1,1],[1,1]]\")\n    print('Expected output:', \"leaf node with val=true\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 427. Construct Quad Tree\nfunc Solve174(args ...any) any {\n\tanswer := make([]any, 0, len(args))\n\tanswer = append(answer, args...)\n\treturn answer\n}\n\nfunc main() {\n\tfmt.Println(\"427. Construct Quad Tree\")\n\tfmt.Println(\"Sample input:\", \"grid=[[1,1],[1,1]]\")\n\tfmt.Println(\"Expected output:\", \"leaf node with val=true\")\n\tfmt.Println(\"Call Solve174(...) with parsed arguments for this problem.\")\n}\n"
