    "sourcePythonCode": "class Solution:\n    def maxSubarraySumCircular(self, nums: List[int]) -> int:\n        pmi, pmx = 0, -inf\n        ans, s, smi = -inf, 0, inf\n        for x in nums:\n            s += x\n            ans = max(ans, s - pmi)\n            smi = min(smi, s - pmx)\n            pmi = min(pmi, s)\n            pmx = max(pmx, s)\n        return max(ans, s - smi)",
