    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0004.Median of Two Sorted Arrays",
    "sourcePythonCode": "class Solution:\n    def findMedianSortedArrays(self, nums1: List[int], nums2: List[int]) -> float:\n        def f(i: int, j: int, k: int) -> int:\n            if i >= m:\n                return nums2[j + k - 1]\n            if j >= n:\n                return nums1[i + k - 1]\n            if k == 1:\n                return min(nums1[i], nums2[j])\n            p = k // 2\n            x = nums1[i + p - 1] if i + p - 1 < m else inf\n            y = nums2[j + p - 1] if j + p - 1 < n else inf\n            return f(i + p, j, k - p) if x < y else f(i, j + p, k - p)\n\n        m, n = len(nums1), len(nums2)\n        a = f(0, 0, (m + n + 1) // 2)\n        b = f(0, 0, (m + n + 2) // 2)\n        return (a + b) / 2",
    "sourceGoCode": "func findMedianSortedArrays(nums1 []int, nums2 []int) float64 {\n\tm, n := len(nums1), len(nums2)\n\tvar f func(i, j, k int) int\n\tf = func(i, j, k int) int {\n\t\tif i >= m {\n\t\t\treturn nums2[j+k-1]\n\t\t}\n\t\tif j >= n {\n\t\t\treturn nums1[i+k-1]\n\t\t}\n\t\tif k == 1 {\n\t\t\treturn min(nums1[i], nums2[j])\n\t\t}\n\t\tp := k / 2\n\t\tx, y := 1<<30, 1<<30\n\t\tif ni := i + p - 1; ni < m {\n\t\t\tx = nums1[ni]\n\t\t}\n\t\tif nj := j + p - 1; nj < n {\n\t\t\ty = nums2[nj]\n\t\t}\n\t\tif x < y {\n\t\t\treturn f(i+p, j, k-p)\n\t\t}\n\t\treturn f(i, j+p, k-p)\n\t}\n\ta, b := f(0, 0, (m+n+1)/2), f(0, 0, (m+n+2)/2)\n\treturn float64(a+b) / 2.0\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 4. Median of Two Sorted Arrays.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    nums = list(args[0]) if args else []\n    target = args[1] if len(args) > 1 else None\n    lo, hi = 0, len(nums)\n    while lo < hi:\n        mid = (lo + hi) // 2\n        if target is not None and nums[mid] < target:\n            lo = mid + 1\n        else:\n            hi = mid\n    return lo\n\n\n\nmedian_of_two_sorted_arrays = solve\n\n\nif __name__ == \"__main__\":\n    print(\"4. Median of Two Sorted Arrays\")\n    print('Sample input:', \"nums1=[1,3], nums2=[2]\")\n    print('Expected output:', \"2.0\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
