    "sourcePythonCode": "class Solution:\n    def findMaximizedCapital(\n        self, k: int, w: int, profits: List[int], capital: List[int]\n    ) -> int:\n        h1 = [(c, p) for c, p in zip(capital, profits)]\n        heapify(h1)\n        h2 = []\n        while k:\n            while h1 and h1[0][0] <= w:\n                heappush(h2, -heappop(h1)[1])\n            if not h2:\n                break\n            w -= heappop(h2)\n            k -= 1\n        return w",
    "sourceGoCode": "func findMaximizedCapital(k int, w int, profits []int, capital []int) int {\n\tq1 := hp2{}\n\tfor i, c := range capital {\n\t\theap.Push(&q1, pair{c, profits[i]})\n\t}\n\tq2 := hp{}\n\tfor k > 0 {\n\t\tfor len(q1) > 0 && q1[0].c <= w {\n\t\t\theap.Push(&q2, heap.Pop(&q1).(pair).p)\n\t\t}\n\t\tif q2.Len() == 0 {\n\t\t\tbreak\n\t\t}\n\t\tw += heap.Pop(&q2).(int)\n\t\tk--\n\t}\n\treturn w\n}\n\ntype hp struct{ sort.IntSlice }\n\nfunc (h hp) Less(i, j int) bool { return h.IntSlice[i] > h.IntSlice[j] }\nfunc (h *hp) Push(v any)        { h.IntSlice = append(h.IntSlice, v.(int)) }\nfunc (h *hp) Pop() any {\n\ta := h.IntSlice\n\tv := a[len(a)-1]\n\th.IntSlice = a[:len(a)-1]\n\treturn v\n}\n\ntype pair struct{ c, p int }\ntype hp2 []pair\n\nfunc (h hp2) Len() int           { return len(h) }\nfunc (h hp2) Less(i, j int) bool { return h[i].c < h[j].c }\nfunc (h hp2) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }\nfunc (h *hp2) Push(v any)        { *h = append(*h, v.(pair)) }\nfunc (h *hp2) Pop() any          { a := *h; v := a[len(a)-1]; *h = a[:len(a)-1]; return v }",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 502. IPO.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nipo = solve\n\n\nif __name__ == \"__main__\":\n    print(\"502. IPO\")\n    print('Sample input:', \"k=2, w=0, profits=[1,2,3], capital=[0,1,1]\")\n    print('Expected output:', \"4\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
