    "sourcePythonCode": "class Solution:\n    def kSmallestPairs(\n        self, nums1: List[int], nums2: List[int], k: int\n    ) -> List[List[int]]:\n        q = [[u + nums2[0], i, 0] for i, u in enumerate(nums1[:k])]\n        heapify(q)\n        ans = []\n        while q and k > 0:\n            _, i, j = heappop(q)\n            ans.append([nums1[i], nums2[j]])\n            k -= 1\n            if j + 1 < len(nums2):\n                heappush(q, [nums1[i] + nums2[j + 1], i, j + 1])\n        return ans",
    "sourceGoCode": "func kSmallestPairs(nums1, nums2 []int, k int) (ans [][]int) {\n\tm, n := len(nums1), len(nums2)\n\th := hp{nil, nums1, nums2}\n\tfor i := 0; i < k && i < m; i++ {\n\t\th.data = append(h.data, pair{i, 0})\n\t}\n\tfor h.Len() > 0 && len(ans) < k {\n\t\tp := heap.Pop(&h).(pair)\n\t\ti, j := p.i, p.j\n\t\tans = append(ans, []int{nums1[i], nums2[j]})\n\t\tif j+1 < n {\n\t\t\theap.Push(&h, pair{i, j + 1})\n\t\t}\n\t}\n\treturn\n}\n\ntype pair struct{ i, j int }\ntype hp struct {\n\tdata         []pair\n\tnums1, nums2 []int\n}\n\nfunc (h hp) Len() int { return len(h.data) }\nfunc (h hp) Less(i, j int) bool {\n\ta, b := h.data[i], h.data[j]\n\treturn h.nums1[a.i]+h.nums2[a.j] < h.nums1[b.i]+h.nums2[b.j]\n}\nfunc (h hp) Swap(i, j int) { h.data[i], h.data[j] = h.data[j], h.data[i] }\nfunc (h *hp) Push(v any)   { h.data = append(h.data, v.(pair)) }\nfunc (h *hp) Pop() any     { a := h.data; v := a[len(a)-1]; h.data = a[:len(a)-1]; return v }",
