    "leetcodeMainPath": "leetcode-main/solution/0200-0299/0295.Find Median from Data Stream",
    "sourcePythonCode": "class MedianFinder:\n\n    def __init__(self):\n        self.minq = []\n        self.maxq = []\n\n    def addNum(self, num: int) -> None:\n        heappush(self.minq, -heappushpop(self.maxq, -num))\n        if len(self.minq) - len(self.maxq) > 1:\n            heappush(self.maxq, -heappop(self.minq))\n\n    def findMedian(self) -> float:\n        if len(self.minq) == len(self.maxq):\n            return (self.minq[0] - self.maxq[0]) / 2\n        return self.minq[0]\n\n\n# Your MedianFinder object will be instantiated and called as such:\n# obj = MedianFinder()\n# obj.addNum(num)\n# param_2 = obj.findMedian()",
    "sourceGoCode": "type MedianFinder struct {\n\tminq hp\n\tmaxq hp\n}\n\nfunc Constructor() MedianFinder {\n\treturn MedianFinder{hp{}, hp{}}\n}\n\nfunc (this *MedianFinder) AddNum(num int) {\n\tminq, maxq := &this.minq, &this.maxq\n\theap.Push(maxq, -num)\n\theap.Push(minq, -heap.Pop(maxq).(int))\n\tif minq.Len()-maxq.Len() > 1 {\n\t\theap.Push(maxq, -heap.Pop(minq).(int))\n\t}\n}\n\nfunc (this *MedianFinder) FindMedian() float64 {\n\tminq, maxq := this.minq, this.maxq\n\tif minq.Len() == maxq.Len() {\n\t\treturn float64(minq.IntSlice[0]-maxq.IntSlice[0]) / 2\n\t}\n\treturn float64(minq.IntSlice[0])\n}\n\ntype hp struct{ sort.IntSlice }\n\nfunc (h hp) Less(i, j int) bool { return h.IntSlice[i] < h.IntSlice[j] }\nfunc (h *hp) Push(v any)        { h.IntSlice = append(h.IntSlice, v.(int)) }\nfunc (h *hp) Pop() any {\n\ta := h.IntSlice\n\tv := a[len(a)-1]\n\th.IntSlice = a[:len(a)-1]\n\treturn v\n}\n\n/**\n * Your MedianFinder object will be instantiated and called as such:\n * obj := Constructor();\n * obj.AddNum(num);\n * param_2 := obj.FindMedian();\n */",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 295. Find Median from Data Stream.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nfind_median_from_data_stream = solve\n\n\nif __name__ == \"__main__\":\n    print(\"295. Find Median from Data Stream\")\n    print('Sample input:', \"add 1, add 2, find, add 3, find\")\n    print('Expected output:', \"[null,null,1.5,null,2]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
