    "leetcodeMainPath": "leetcode-main/solution/0100-0199/0149.Max Points on a Line",
    "sourcePythonCode": "class Solution:\n    def maxPoints(self, points: List[List[int]]) -> int:\n        n = len(points)\n        ans = 1\n        for i in range(n):\n            x1, y1 = points[i]\n            for j in range(i + 1, n):\n                x2, y2 = points[j]\n                cnt = 2\n                for k in range(j + 1, n):\n                    x3, y3 = points[k]\n                    a = (y2 - y1) * (x3 - x1)\n                    b = (y3 - y1) * (x2 - x1)\n                    cnt += a == b\n                ans = max(ans, cnt)\n        return ans",
    "sourceGoCode": "func maxPoints(points [][]int) int {\n\tn := len(points)\n\tans := 1\n\tfor i := 0; i < n; i++ {\n\t\tx1, y1 := points[i][0], points[i][1]\n\t\tfor j := i + 1; j < n; j++ {\n\t\t\tx2, y2 := points[j][0], points[j][1]\n\t\t\tcnt := 2\n\t\t\tfor k := j + 1; k < n; k++ {\n\t\t\t\tx3, y3 := points[k][0], points[k][1]\n\t\t\t\ta := (y2 - y1) * (x3 - x1)\n\t\t\t\tb := (y3 - y1) * (x2 - x1)\n\t\t\t\tif a == b {\n\t\t\t\t\tcnt++\n\t\t\t\t}\n\t\t\t}\n\t\t\tif ans < cnt {\n\t\t\t\tans = cnt\n\t\t\t}\n\t\t}\n\t}\n\treturn ans\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 149. Max Points on a Line.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nmax_points_on_a_line = solve\n\n\nif __name__ == \"__main__\":\n    print(\"149. Max Points on a Line\")\n    print('Sample input:', \"points=[[1,1],[2,2],[3,3],[3,4]]\")\n    print('Expected output:', \"3\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
