    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0064.Minimum Path Sum",
    "sourcePythonCode": "class Solution:\n    def minPathSum(self, grid: List[List[int]]) -> int:\n        m, n = len(grid), len(grid[0])\n        f = [[0] * n for _ in range(m)]\n        f[0][0] = grid[0][0]\n        for i in range(1, m):\n            f[i][0] = f[i - 1][0] + grid[i][0]\n        for j in range(1, n):\n            f[0][j] = f[0][j - 1] + grid[0][j]\n        for i in range(1, m):\n            for j in range(1, n):\n                f[i][j] = min(f[i - 1][j], f[i][j - 1]) + grid[i][j]\n        return f[-1][-1]",
    "sourceGoCode": "func minPathSum(grid [][]int) int {\n\tm, n := len(grid), len(grid[0])\n\tf := make([][]int, m)\n\tfor i := range f {\n\t\tf[i] = make([]int, n)\n\t}\n\tf[0][0] = grid[0][0]\n\tfor i := 1; i < m; i++ {\n\t\tf[i][0] = f[i-1][0] + grid[i][0]\n\t}\n\tfor j := 1; j < n; j++ {\n\t\tf[0][j] = f[0][j-1] + grid[0][j]\n\t}\n\tfor i := 1; i < m; i++ {\n\t\tfor j := 1; j < n; j++ {\n\t\t\tf[i][j] = min(f[i-1][j], f[i][j-1]) + grid[i][j]\n\t\t}\n\t}\n\treturn f[m-1][n-1]\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 64. Minimum Path Sum.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nminimum_path_sum = solve\n\n\nif __name__ == \"__main__\":\n    print(\"64. Minimum Path Sum\")\n    print('Sample input:', \"grid=[[1,3,1],[1,5,1],[4,2,1]]\")\n    print('Expected output:', \"7\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
