    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0063.Unique Paths II",
    "sourcePythonCode": "class Solution:\n    def uniquePathsWithObstacles(self, obstacleGrid: List[List[int]]) -> int:\n        @cache\n        def dfs(i: int, j: int) -> int:\n            if i >= m or j >= n or obstacleGrid[i][j]:\n                return 0\n            if i == m - 1 and j == n - 1:\n                return 1\n            return dfs(i + 1, j) + dfs(i, j + 1)\n\n        m, n = len(obstacleGrid), len(obstacleGrid[0])\n        return dfs(0, 0)",
    "sourceGoCode": "func uniquePathsWithObstacles(obstacleGrid [][]int) int {\n\tm, n := len(obstacleGrid), len(obstacleGrid[0])\n\tf := make([][]int, m)\n\tfor i := range f {\n\t\tf[i] = make([]int, n)\n\t\tfor j := range f[i] {\n\t\t\tf[i][j] = -1\n\t\t}\n\t}\n\tvar dfs func(i, j int) int\n\tdfs = func(i, j int) int {\n\t\tif i >= m || j >= n || obstacleGrid[i][j] == 1 {\n\t\t\treturn 0\n\t\t}\n\t\tif i == m-1 && j == n-1 {\n\t\t\treturn 1\n\t\t}\n\t\tif f[i][j] == -1 {\n\t\t\tf[i][j] = dfs(i+1, j) + dfs(i, j+1)\n\t\t}\n\t\treturn f[i][j]\n\t}\n\treturn dfs(0, 0)\n}",
