    "videoUrl": "https://www.youtube.com/results?search_query=LeetCode+5+Longest+Palindromic+Substring+solution",
    "leetcodeMainPath": "leetcode-main/solution/0000-0099/0005.Longest Palindromic Substring",
    "sourcePythonCode": "class Solution:\n    def longestPalindrome(self, s: str) -> str:\n        n = len(s)\n        f = [[True] * n for _ in range(n)]\n        k, mx = 0, 1\n        for i in range(n - 2, -1, -1):\n            for j in range(i + 1, n):\n                f[i][j] = False\n                if s[i] == s[j]:\n                    f[i][j] = f[i + 1][j - 1]\n                    if f[i][j] and mx < j - i + 1:\n                        k, mx = i, j - i + 1\n        return s[k : k + mx]",
    "sourceGoCode": "func longestPalindrome(s string) string {\n\tn := len(s)\n\tf := make([][]bool, n)\n\tfor i := range f {\n\t\tf[i] = make([]bool, n)\n\t\tfor j := range f[i] {\n\t\t\tf[i][j] = true\n\t\t}\n\t}\n\tk, mx := 0, 1\n\tfor i := n - 2; i >= 0; i-- {\n\t\tfor j := i + 1; j < n; j++ {\n\t\t\tf[i][j] = false\n\t\t\tif s[i] == s[j] {\n\t\t\t\tf[i][j] = f[i+1][j-1]\n\t\t\t\tif f[i][j] && mx < j-i+1 {\n\t\t\t\t\tmx = j - i + 1\n\t\t\t\t\tk = i\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t}\n\treturn s[k : k+mx]\n}",
