    "sourcePythonCode": "class Solution:\n    def containsDuplicate(self, nums: List[int]) -> bool:\n        return any(a == b for a, b in pairwise(sorted(nums)))",
    "sourceGoCode": "func containsDuplicate(nums []int) bool {\n\tsort.Ints(nums)\n\tfor i, v := range nums[1:] {\n\t\tif v == nums[i] {\n\t\t\treturn true\n\t\t}\n\t}\n\treturn false\n}",
