    "sourcePythonCode": "class Solution:\n    def numDecodings(self, s: str) -> int:\n        n = len(s)\n        f = [1] + [0] * n\n        for i, c in enumerate(s, 1):\n            if c != \"0\":\n                f[i] = f[i - 1]\n            if i > 1 and s[i - 2] != \"0\" and int(s[i - 2 : i]) <= 26:\n                f[i] += f[i - 2]\n        return f[n]",
    "sourceGoCode": "func numDecodings(s string) int {\n\tn := len(s)\n\tf := make([]int, n+1)\n\tf[0] = 1\n\tfor i := 1; i <= n; i++ {\n\t\tif s[i-1] != '0' {\n\t\t\tf[i] = f[i-1]\n\t\t}\n\t\tif i > 1 && (s[i-2] == '1' || (s[i-2] == '2' && s[i-1] <= '6')) {\n\t\t\tf[i] += f[i-2]\n\t\t}\n\t}\n\treturn f[n]\n}",
