    "videoUrl": "https://www.youtube.com/results?search_query=LeetCode+417+Pacific+Atlantic+Water+Flow+solution",
    "leetcodeMainPath": "leetcode-main/solution/0400-0499/0417.Pacific Atlantic Water Flow",
    "sourcePythonCode": "class Solution:\n    def pacificAtlantic(self, heights: List[List[int]]) -> List[List[int]]:\n        def bfs(q: Deque[Tuple[int, int]], vis: List[List[bool]]) -> None:\n            while q:\n                x, y = q.popleft()\n                for dx, dy in pairwise(dirs):\n                    nx, ny = x + dx, y + dy\n                    if (\n                        0 <= nx < m\n                        and 0 <= ny < n\n                        and not vis[nx][ny]\n                        and heights[nx][ny] >= heights[x][y]\n                    ):\n                        vis[nx][ny] = True\n                        q.append((nx, ny))\n\n        m, n = len(heights), len(heights[0])\n        vis1 = [[False] * n for _ in range(m)]\n        vis2 = [[False] * n for _ in range(m)]\n        q1: Deque[Tuple[int, int]] = deque()\n        q2: Deque[Tuple[int, int]] = deque()\n        dirs = (-1, 0, 1, 0, -1)\n\n        for i in range(m):\n            q1.append((i, 0))\n            vis1[i][0] = True\n            q2.append((i, n - 1))\n            vis2[i][n - 1] = True\n\n        for j in range(n):\n            q1.append((0, j))\n            vis1[0][j] = True\n            q2.append((m - 1, j))\n            vis2[m - 1][j] = True\n\n        bfs(q1, vis1)\n        bfs(q2, vis2)\n\n        return [(i, j) for i in range(m) for j in range(n) if vis1[i][j] and vis2[i][j]]",
    "sourceGoCode": "func pacificAtlantic(heights [][]int) [][]int {\n\tm, n := len(heights), len(heights[0])\n\tvis1 := make([][]bool, m)\n\tvis2 := make([][]bool, m)\n\tfor i := range vis1 {\n\t\tvis1[i] = make([]bool, n)\n\t\tvis2[i] = make([]bool, n)\n\t}\n\tq1, q2 := [][2]int{}, [][2]int{}\n\tdirs := [5]int{-1, 0, 1, 0, -1}\n\n\tfor i := 0; i < m; i++ {\n\t\tq1 = append(q1, [2]int{i, 0})\n\t\tvis1[i][0] = true\n\t\tq2 = append(q2, [2]int{i, n - 1})\n\t\tvis2[i][n-1] = true\n\t}\n\tfor j := 0; j < n; j++ {\n\t\tq1 = append(q1, [2]int{0, j})\n\t\tvis1[0][j] = true\n\t\tq2 = append(q2, [2]int{m - 1, j})\n\t\tvis2[m-1][j] = true\n\t}\n\n\tbfs := func(q [][2]int, vis [][]bool) {\n\t\tfor len(q) > 0 {\n\t\t\tx, y := q[0][0], q[0][1]\n\t\t\tq = q[1:]\n\t\t\tfor k := 0; k < 4; k++ {\n\t\t\t\tnx, ny := x+dirs[k], y+dirs[k+1]\n\t\t\t\tif nx >= 0 && nx < m && ny >= 0 && ny < n &&\n\t\t\t\t\t!vis[nx][ny] && heights[nx][ny] >= heights[x][y] {\n\t\t\t\t\tvis[nx][ny] = true\n\t\t\t\t\tq = append(q, [2]int{nx, ny})\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t}\n\n\tbfs(q1, vis1)\n\tbfs(q2, vis2)\n\n\tvar ans [][]int\n\tfor i := 0; i < m; i++ {\n\t\tfor j := 0; j < n; j++ {\n\t\t\tif vis1[i][j] && vis2[i][j] {\n\t\t\t\tans = append(ans, []int{i, j})\n\t\t\t}\n\t\t}\n\t}\n\treturn ans\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 417. Pacific Atlantic Water Flow.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    graph = {}\n    for a, b in (args[1] if len(args) > 1 else []):\n        graph.setdefault(a, []).append(b)\n        graph.setdefault(b, []).append(a)\n    return graph\n\n\n\npacific_atlantic_water_flow = solve\n\n\nif __name__ == \"__main__\":\n    print(\"417. Pacific Atlantic Water Flow\")\n    print('Sample input:', \"heights=[[1,2],[4,3]]\")\n    print('Expected output:', \"[[0,1],[1,0],[1,1]]\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 417. Pacific Atlantic Water Flow\nfunc Solve216(args ...any) any {\n\treturn args\n}\n\nfunc main() {\n\tfmt.Println(\"417. Pacific Atlantic Water Flow\")\n\tfmt.Println(\"Sample input:\", \"heights=[[1,2],[4,3]]\")\n\tfmt.Println(\"Expected output:\", \"[[0,1],[1,0],[1,1]]\")\n\tfmt.Println(\"Call Solve216(...) with parsed arguments for this problem.\")\n}\n"
