    "videoUrl": "https://www.youtube.com/results?search_query=LeetCode+269+Alien+Dictionary+solution",
    "leetcodeMainPath": "leetcode-main/solution/0200-0299/0269.Alien Dictionary",
    "sourcePythonCode": "class Solution:\n    def alienOrder(self, words: List[str]) -> str:\n        g = [[False] * 26 for _ in range(26)]\n        s = [False] * 26\n        cnt = 0\n        n = len(words)\n        for i in range(n - 1):\n            for c in words[i]:\n                if cnt == 26:\n                    break\n                o = ord(c) - ord('a')\n                if not s[o]:\n                    cnt += 1\n                    s[o] = True\n            m = len(words[i])\n            for j in range(m):\n                if j >= len(words[i + 1]):\n                    return ''\n                c1, c2 = words[i][j], words[i + 1][j]\n                if c1 == c2:\n                    continue\n                o1, o2 = ord(c1) - ord('a'), ord(c2) - ord('a')\n                if g[o2][o1]:\n                    return ''\n                g[o1][o2] = True\n                break\n        for c in words[n - 1]:\n            if cnt == 26:\n                break\n            o = ord(c) - ord('a')\n            if not s[o]:\n                cnt += 1\n                s[o] = True\n\n        indegree = [0] * 26\n        for i in range(26):\n            for j in range(26):\n                if i != j and s[i] and s[j] and g[i][j]:\n                    indegree[j] += 1\n        q = deque()\n        ans = []\n        for i in range(26):\n            if s[i] and indegree[i] == 0:\n                q.append(i)\n        while q:\n            t = q.popleft()\n            ans.append(chr(t + ord('a')))\n            for i in range(26):\n                if s[i] and i != t and g[t][i]:\n                    indegree[i] -= 1\n                    if indegree[i] == 0:\n                        q.append(i)\n        return '' if len(ans) < cnt else ''.join(ans)",
    "sourceGoCode": "func alienOrder(words []string) string {\n\tg := [26][26]bool{}\n\ts := [26]bool{}\n\tcnt := 0\n\tn := len(words)\n\tfor i := 0; i < n-1; i++ {\n\t\tfor _, c := range words[i] {\n\t\t\tif cnt == 26 {\n\t\t\t\tbreak\n\t\t\t}\n\t\t\tc -= 'a'\n\t\t\tif !s[c] {\n\t\t\t\tcnt++\n\t\t\t\ts[c] = true\n\t\t\t}\n\t\t}\n\t\tm := len(words[i])\n\t\tfor j := 0; j < m; j++ {\n\t\t\tif j >= len(words[i+1]) {\n\t\t\t\treturn \"\"\n\t\t\t}\n\t\t\tc1, c2 := words[i][j]-'a', words[i+1][j]-'a'\n\t\t\tif c1 == c2 {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tif g[c2][c1] {\n\t\t\t\treturn \"\"\n\t\t\t}\n\t\t\tg[c1][c2] = true\n\t\t\tbreak\n\t\t}\n\t}\n\tfor _, c := range words[n-1] {\n\t\tif cnt == 26 {\n\t\t\tbreak\n\t\t}\n\t\tc -= 'a'\n\t\tif !s[c] {\n\t\t\tcnt++\n\t\t\ts[c] = true\n\t\t}\n\t}\n\n\tinDegree := [26]int{}\n\tfor _, out := range g {\n\t\tfor i, v := range out {\n\t\t\tif v {\n\t\t\t\tinDegree[i]++\n\t\t\t}\n\t\t}\n\t}\n\tq := []int{}\n\tfor i, in := range inDegree {\n\t\tif in == 0 && s[i] {\n\t\t\tq = append(q, i)\n\t\t}\n\t}\n\tans := \"\"\n\tfor len(q) > 0 {\n\t\tt := q[0]\n\t\tq = q[1:]\n\t\tans += string(t + 'a')\n\t\tfor i, v := range g[t] {\n\t\t\tif v {\n\t\t\t\tinDegree[i]--\n\t\t\t\tif inDegree[i] == 0 && s[i] {\n\t\t\t\t\tq = append(q, i)\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t}\n\tif len(ans) < cnt {\n\t\treturn \"\"\n\t}\n\treturn ans\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 269. Alien Dictionary.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    graph = {}\n    for a, b in (args[1] if len(args) > 1 else []):\n        graph.setdefault(a, []).append(b)\n        graph.setdefault(b, []).append(a)\n    return graph\n\n\n\nalien_dictionary = solve\n\n\nif __name__ == \"__main__\":\n    print(\"269. Alien Dictionary\")\n    print('Sample input:', \"words=[\\\"wrt\\\",\\\"wrf\\\",\\\"er\\\",\\\"ett\\\",\\\"rftt\\\"]\")\n    print('Expected output:', \"\\\"wertf\\\"\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 269. Alien Dictionary\nfunc Solve217(args ...any) any {\n\treturn args\n}\n\nfunc main() {\n\tfmt.Println(\"269. Alien Dictionary\")\n\tfmt.Println(\"Sample input:\", \"words=[\\\"wrt\\\",\\\"wrf\\\",\\\"er\\\",\\\"ett\\\",\\\"rftt\\\"]\")\n\tfmt.Println(\"Expected output:\", \"\\\"wertf\\\"\")\n\tfmt.Println(\"Call Solve217(...) with parsed arguments for this problem.\")\n}\n"
