    "sourcePythonCode": "class Solution:\n    def minMeetingRooms(self, intervals: List[List[int]]) -> int:\n        m = max(e[1] for e in intervals)\n        d = [0] * (m + 1)\n        for l, r in intervals:\n            d[l] += 1\n            d[r] -= 1\n        ans = s = 0\n        for v in d:\n            s += v\n            ans = max(ans, s)\n        return ans",
