    "sourcePythonCode": "# Definition for a binary tree node.\n# class TreeNode:\n#     def __init__(self, val=0, left=None, right=None):\n#         self.val = val\n#         self.left = left\n#         self.right = right\nclass Solution:\n    def isSubtree(self, root: Optional[TreeNode], subRoot: Optional[TreeNode]) -> bool:\n        def same(p: Optional[TreeNode], q: Optional[TreeNode]) -> bool:\n            if p is None or q is None:\n                return p is q\n            return p.val == q.val and same(p.left, q.left) and same(p.right, q.right)\n\n        if root is None:\n            return False\n        return (\n            same(root, subRoot)\n            or self.isSubtree(root.left, subRoot)\n            or self.isSubtree(root.right, subRoot)\n        )",
    "sourceGoCode": "/**\n * Definition for a binary tree node.\n * type TreeNode struct {\n *     Val int\n *     Left *TreeNode\n *     Right *TreeNode\n * }\n */\nfunc isSubtree(root *TreeNode, subRoot *TreeNode) bool {\n\tvar same func(p, q *TreeNode) bool\n\tsame = func(p, q *TreeNode) bool {\n\t\tif p == nil || q == nil {\n\t\t\treturn p == q\n\t\t}\n\t\treturn p.Val == q.Val && same(p.Left, q.Left) && same(p.Right, q.Right)\n\t}\n\tif root == nil {\n\t\treturn false\n\t}\n\treturn same(root, subRoot) || isSubtree(root.Left, subRoot) || isSubtree(root.Right, subRoot)\n}",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 572. Subtree of Another Tree.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nsubtree_of_another_tree = solve\n\n\nif __name__ == \"__main__\":\n    print(\"572. Subtree of Another Tree\")\n    print('Sample input:', \"root=[3,4,5,1,2], subRoot=[4,1,2]\")\n    print('Expected output:', \"true\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
