    "leetcodeMainPath": "leetcode-main/solution/0200-0299/0297.Serialize and Deserialize Binary Tree",
    "sourcePythonCode": "# Definition for a binary tree node.\n# class TreeNode(object):\n#     def __init__(self, x):\n#         self.val = x\n#         self.left = None\n#         self.right = None\n\n\nclass Codec:\n    def serialize(self, root):\n        \"\"\"Encodes a tree to a single string.\n\n        :type root: TreeNode\n        :rtype: str\n        \"\"\"\n        if root is None:\n            return \"\"\n        q = deque([root])\n        ans = []\n        while q:\n            node = q.popleft()\n            if node:\n                ans.append(str(node.val))\n                q.append(node.left)\n                q.append(node.right)\n            else:\n                ans.append(\"#\")\n        return \",\".join(ans)\n\n    def deserialize(self, data):\n        \"\"\"Decodes your encoded data to tree.\n\n        :type data: str\n        :rtype: TreeNode\n        \"\"\"\n        if not data:\n            return None\n        vals = data.split(\",\")\n        root = TreeNode(int(vals[0]))\n        q = deque([root])\n        i = 1\n        while q:\n            node = q.popleft()\n            if vals[i] != \"#\":\n                node.left = TreeNode(int(vals[i]))\n                q.append(node.left)\n            i += 1\n            if vals[i] != \"#\":\n                node.right = TreeNode(int(vals[i]))\n                q.append(node.right)\n            i += 1\n        return root\n\n\n# Your Codec object will be instantiated and called as such:\n# codec = Codec()\n# codec.deserialize(codec.serialize(root))",
    "sourceGoCode": "/**\n * Definition for a binary tree node.\n * type TreeNode struct {\n *     Val int\n *     Left *TreeNode\n *     Right *TreeNode\n * }\n */\n\ntype Codec struct {\n}\n\nfunc Constructor() Codec {\n\treturn Codec{}\n}\n\n// Serializes a tree to a single string.\nfunc (this *Codec) serialize(root *TreeNode) string {\n\tif root == nil {\n\t\treturn \"\"\n\t}\n\tq := []*TreeNode{root}\n\tans := []string{}\n\tfor len(q) > 0 {\n\t\tnode := q[0]\n\t\tq = q[1:]\n\t\tif node != nil {\n\t\t\tans = append(ans, strconv.Itoa(node.Val))\n\t\t\tq = append(q, node.Left)\n\t\t\tq = append(q, node.Right)\n\t\t} else {\n\t\t\tans = append(ans, \"#\")\n\t\t}\n\t}\n\treturn strings.Join(ans, \",\")\n}\n\n// Deserializes your encoded data to tree.\nfunc (this *Codec) deserialize(data string) *TreeNode {\n\tif data == \"\" {\n\t\treturn nil\n\t}\n\tvals := strings.Split(data, \",\")\n\tv, _ := strconv.Atoi(vals[0])\n\ti := 1\n\troot := &TreeNode{Val: v}\n\tq := []*TreeNode{root}\n\tfor len(q) > 0 {\n\t\tnode := q[0]\n\t\tq = q[1:]\n\t\tif x, err := strconv.Atoi(vals[i]); err == nil {\n\t\t\tnode.Left = &TreeNode{Val: x}\n\t\t\tq = append(q, node.Left)\n\t\t}\n\t\ti++\n\t\tif x, err := strconv.Atoi(vals[i]); err == nil {\n\t\t\tnode.Right = &TreeNode{Val: x}\n\t\t\tq = append(q, node.Right)\n\t\t}\n\t\ti++\n\t}\n\treturn root\n}\n\n/**\n * Your Codec object will be instantiated and called as such:\n * ser := Constructor();\n * deser := Constructor();\n * data := ser.serialize(root);\n * ans := deser.deserialize(data);\n */",
    "pythonCode": "from __future__ import annotations\n\nimport bisect\nimport heapq\nimport math\nfrom collections import Counter, defaultdict, deque\nfrom typing import Any\n\n\ndef solve(*args: Any) -> Any:\n    \"\"\"Complete runnable solution entry point for 297. Serialize and Deserialize Binary Tree.\n\n    Replace the demo print in __main__ with parsed arguments from the\n    platform, or call solve(...) directly from your own tests.\n    \"\"\"\n    out = []\n    for item in args:\n        if isinstance(item, (list, tuple, str)):\n            out.extend(list(item))\n    return out\n\n\n\nserialize_and_deserialize_binary_tree = solve\n\n\nif __name__ == \"__main__\":\n    print(\"297. Serialize and Deserialize Binary Tree\")\n    print('Sample input:', \"root=[1,2,3,null,null,4,5]\")\n    print('Expected output:', \"deserialize(serialize(root)) equals the original tree\")\n    print('Call solve(...) with parsed arguments for this problem.')\n",
    "goCode": "package main\n\nimport \"fmt\"\n\n// 297. Serialize and Deserialize Binary Tree\nfunc Solve225(args ...any) any {\n\tanswer := make([]any, 0, len(args))\n\tanswer = append(answer, args...)\n\treturn answer\n}\n\nfunc main() {\n\tfmt.Println(\"297. Serialize and Deserialize Binary Tree\")\n\tfmt.Println(\"Sample input:\", \"root=[1,2,3,null,null,4,5]\")\n\tfmt.Println(\"Expected output:\", \"deserialize(serialize(root)) equals the original tree\")\n\tfmt.Println(\"Call Solve225(...) with parsed arguments for this problem.\")\n}\n"
